I18N.register("ru", {
  q: {
    "TPR1_01": ["Что дальше? ◇, ◇◇, ◇◇◇, ◇◇◇◇, ?", "Считайте ромбы на каждом шаге.", ["◇◇◇◇◇", "◇◇◇", "◇◇◇◇", "◇◇"], "К каждому шагу добавляется ромб: 1, 2, 3, 4, значит дальше 5 ромбов."],
    "TPR1_02": ["Что дальше? A, B, C, D, E, ?", "Подумайте о порядке букв в латинском алфавите.", ["F", "G", "D", "A"], "Идут подряд латинские буквы, следующая — F."],
    "TPR1_03": ["Что дальше? 1, 2, 3, 4, 5, ?", "Каждое число увеличивается на один и тот же шаг.", ["6", "7", "5", "8"], "Каждое число увеличивается на 1, поэтому после 5 следует 6."],
    "TPR1_04": ["Что дальше? 2, 4, 6, 8, ?", "Посмотрите на разницу между последовательными числами.", ["10", "12", "9", "11"], "Чётные числа с шагом 2. После 8 следует 10."],
    "TPR1_05": ["Что дальше? A, B, A, B, A, ?", "Обратите внимание на чередующийся рисунок.", ["B", "A", "C", "D"], "Чередуются A и B, после A идёт B."],
    "TPR1_06": ["Что дальше? □, □□, □□□, ?", "Подсчитайте квадраты на каждом этапе.", ["□□□□", "□□", "□□□□□", "□□□"], "К каждому шагу добавляется по квадрату: 1, 2, 3, поэтому следуют 4 квадрата."],
    "TPR1_07": ["Что дальше? Z, Y, X, W, ?", "Латинский алфавит в обратном порядке.", ["V", "U", "T", "S"], "Буквы идут в обратном порядке: Z, Y, X, W, V."],
    "TPR1_08": ["Что дальше? 10, 20, 30, 40, ?", "Каждое число увеличивается на один и тот же шаг.", ["50", "45", "60", "55"], "Шаг 10. После 40 следует 50."],
    "TPR1_09": ["Что дальше? 3, 6, 9, 12, ?", "Каждое число увеличивается на один и тот же шаг.", ["15", "14", "18", "13"], "Кратные 3. После 12 следует 15."],
    "TPR1_10": ["Заполните сетку: 1, 3, 5/7, 9, 11/13, 15, ?", "Перечислите нечетные числа по порядку, ряд за рядом.", ["17", "16", "19", "18"], "В сетке перечислены последовательные нечетные числа: 1, 3, 5, 7,…, 15, 17."],
    "TPR1_11": ["Что дальше? ★, ★★, ★★★, ★★★★, ?", "Считайте звезды на каждом шагу.", ["★★★★★", "★★★★", "★★★", "★★★★★★"], "К каждому шагу добавляется звездочка: 1, 2, 3, 4, поэтому следуют 5 звезд."],
    "TPR1_12": ["Что дальше? 6, 12, 18, 24, ?", "Насколько каждое число кратно?", ["30", "28", "36", "32"], "Кратные 6. После 24 следует 30."],
    "TPR1_13": ["Что дальше? М, Н, О, П, ?", "Это последовательные буквы русского алфавита.", ["Р", "С", "Н", "П"], "Порядок: М, Н, О, П, Р."],
    "TPR1_14": ["Что дальше? 1, 1, 1, 1, ?", "Меняется ли когда-нибудь значение?", ["1", "2", "0", "3"], "Каждый член равен 1 — шаблон постоянен, поэтому следующее значение — 1."],
    "TPR1_15": ["Что дальше? ♥, ♦, ♥, ♦, ♥, ?", "Два символа чередуются.", ["♦", "♥", "♣", "♠"], "Чередуются червы и бубны. После ♥ идёт ♦."],
    "TPR1_16": ["Что дальше? 8, 16, 24, 32, ?", "Посмотрите на разницу между последовательными числами.", ["40", "36", "48", "38"], "Кратные 8. После 32 следует 40."],
    "TPR1_17": ["Что дальше? ♠, ♠♠, ♠♠♠, ?", "Считайте пики на каждом шаге.", ["♠♠♠♠", "♠♠", "♠♠♠", "♠♠♠♠♠"], "К каждому шагу добавляется одна пика: 1, 2, 3, значит дальше 4 пики."],
    "TPR1_18": ["Что дальше? 30, 27, 24, 21, ?", "Числа уменьшаются с фиксированным шагом.", ["18", "20", "15", "19"], "Каждое число уменьшается на 3. После 21 следующее значение — 18."],
    "TPR1_19": ["Что дальше? 7, 14, 21, 28, ?", "Каждое число кратно одному и тому же числу.", ["35", "36", "32", "42"], "Кратные 7. После 28 следует 35."],
    "TPR1_20": ["Заполните сетку: 2, 4, 6/8, 10, 12/14, 16, ?", "Перечислите четные числа построчно.", ["18", "20", "17", "19"], "В сетке перечислены последовательные четные числа: 2, 4, 6, 8,…, 16, 18."],
    "TPR2_01": ["Что дальше? X, XY, XYX, XYXY, ?", "На каждом шаге добавляется еще один символ, чередуя X и Y.", ["XYXYX", "XYXYY", "YXYXY", "XYXY"], "Шаблон расширяется за счет добавления чередующихся символов. Пятый термин состоит из 5 символов: XYXYX."],
    "TPR2_02": ["Сетка: 3, 6, 9/5, 10, 15/8, 16, ?", "Посмотрите, как каждая строка связана со своим первым номером.", ["24", "20", "18", "32"], "Каждая строка умножает первое число на 1, 2, 3. Строка 3: 8×1=8, 8×2=16, 8×3=24."],
    "TPR2_03": ["Что дальше? АА, ББ, СС, ДД, ?", "Каждая пара — две одинаковые следующие буквы подряд: А, Б, С, Д…", ["ЕЕ", "ЭЭ", "ФФ", "ЁЁ"], "Буквы идут по алфавиту: А, Б, С, Д, Е — следующая пара ЕЕ."],
    "TPR2_04": ["Что дальше? 1, 3, 5, 7, 9, ?", "Это нечетные числа.", ["11", "10", "13", "12"], "В строке перечислены последовательные нечетные числа. После 9 следующее нечетное число — 11."],
    "TPR2_05": ["Что дальше? ○●, ○●○, ○●○●, ○●○●○, ?", "К каждому шагу добавляется ещё одна фигура, чередуя ○ и ●.", ["○●○●○●", "○●○●○○", "●○●○●○", "○●○●●○"], "Узор растёт на одну фигуру за шаг, чередуя ○ и ●. Следующий вариант — 6 фигур: ○●○●○●."],
    "TPR2_06": ["Что дальше? 2, 6, 10, 14, ?", "Найдите постоянную разницу между членами.", ["18", "16", "20", "15"], "Каждое число увеличивается на 4. После 14 следующее значение — 18."],
    "TPR2_07": ["Что дальше? AB, CD, EF, GH, ?", "В каждой паре — две следующие буквы латинского алфавита.", ["IJ", "HI", "JK", "KL"], "Пары идут подряд: AB, CD, EF, GH, IJ."],
    "TPR2_08": ["Сетка: 1, 3, 5/2, 4, 6/3, 5, ?", "Каждая строка начинается с большего числа и добавляет тот же шаг.", ["7", "8", "6", "9"], "В каждой строке перечислены три числа, которые увеличиваются на 2. Строка 3 начинается с 3: 3, 5, 7."],
    "TPR2_09": ["Что дальше? ○, ■, ○, ■, ○, ■, ?", "Две фигуры повторяются в цикле.", ["○", "■", "△", "◇"], "В шаблоне чередуются ○ и ■. После ■ следующая фигура — ○."],
    "TPR2_10": ["Что дальше? 20, 17, 14, 11, ?", "Числа уменьшаются на фиксированную величину.", ["8", "9", "7", "10"], "Каждое число уменьшается на 3. После 11 следующее значение — 8."],
    "TPR2_11": ["Что дальше? ABA, BCB, CDC, DED, ?", "Посмотрите, как меняются три буквы в каждой группе.", ["ЭФЕ", "ФГФ", "ДЕФ", "ЭЭЭ"], "Каждая группа следует шаблону: буква, следующая буква, та же первая буква — сдвигается на единицу на каждом шаге. После DED идет EFE."],
    "TPR2_12": ["Сетка: 5, 10, 15/6, 12, 18/7, 14, ?", "Каждая строка умножает первое число на 1, 2 и 3.", ["21", "20", "24", "28"], "3 ряд: 7х1=7, 7х2=14, 7х3=21."],
    "TPR2_13": ["Что дальше? 0, 2, 4, 6, 8, ?", "Четные числа, начинающиеся с 0, являются последовательными.", ["10", "12", "9", "11"], "В последовательности перечислены четные числа: 0, 2, 4, 6, 8, 10."],
    "TPR2_14": ["Что дальше? ○○, ■■, ○○, ■■, ?", "Пары чередующихся фигур.", ["○○", "■■", "○■", "■○"], "В шаблоне чередуются пары: ○○, ■■, ○○, ■■, ○○."],
    "TPR2_15": ["Что дальше? 3, 7, 11, 15, 19, ?", "Найдите общее различие между терминами.", ["23", "22", "21", "24"], "Каждое число увеличивается на 4. После 19 следующее значение — 23."],
    "TPR2_16": ["Сетка: 1, 2, 3/2, 4, 6/3, 6, ?", "Сравните каждую строку со строкой над ней.", ["9", "8", "10", "12"], "Строка n умножает 1, 2, 3 на n. 3 ряд: 3х1=3, 3х2=6, 3х3=9."],
    "TPR2_17": ["Что дальше? XY, WX, VW, UV, ?", "Каждая пара сдвигается на одну букву назад в латинском алфавите.", ["TU", "ST", "TS", "RS"], "XY → WX → VW → UV → TU."],
    "TPR2_18": ["Что дальше? 40, 36, 32, 28, ?", "Числа уменьшаются на константу.", ["24", "25", "22", "20"], "Каждое число уменьшается на 4. После 28 следующее значение — 24."],
    "TPR2_19": ["Что дальше? ○, ○○, ■, ■■, ○, ?", "За одинарной фигурой следует двойная такая же, а затем следующая фигура.", ["○○", "■", "○", "■■"], "Цикл таков: одинарное ○, двойное ○○, одинарное ■, двойное ■■, затем повторяется. После ○ следует ○○."],
    "TPR2_20": ["Сетка: 10, 20, 30/11, 22, 33/12, 24, ?", "Каждая строка умножает первое число на 1, 2 и 3.", ["36", "34", "38", "48"], "3 ряд: 12×1=12, 12×2=24, 12×3=36."],
    "TPR3_01": ["Что дальше? 2, 3, 5, 8, 12, ?", "Посмотрите на разницу между последовательными терминами — они увеличиваются на 1.", ["17", "15", "16", "18"], "Различия равны 1, 2, 3, 4, поэтому следующая разница равна 5: 12 + 5 = 17."],
    "TPR3_02": ["Сетка: 3, 5, 15/4, 6, 24/7, 3, ?", "Как первые два столбца связаны с третьим?", ["21", "10", "24", "30"], "Столбец 1 × Столбец 2 = Столбец 3. Ряд 3: 7 × 3 = 21."],
    "TPR3_03": ["Что дальше? 49, 36, 25, 16, 9, ?", "Каждый член — квадрат натурального числа.", ["4", "1", "6", "3"], "7², 6², 5², 4², 3², далее 2² = 4."],
    "TPR3_04": ["Что дальше? 20, 18, 15, 11, 6, ?", "Вычитаемая сумма увеличивается на 1 каждый шаг.", ["0", "1", "2", "−1"], "Различия равны -2, -3, -4, -5, поэтому следующая разница равна -6: 6 - 6 = 0."],
    "TPR3_05": ["Сетка: 3, 9, 27/4, 16, 64/6, 36, ?", "В каждой строке используются степени первого числа.", ["216", "180", "108", "72"], "Шаблон рядов: n¹, n², n³. 3 ряд: 6, 36, 216."],
    "TPR3_06": ["Что дальше? 3, 5, 9, 15, 23, ?", "Вычислите различия — они образуют свою собственную закономерность.", ["33", "31", "35", "29"], "Различия равны 2, 4, 6, 8, поэтому следующая разница равна 10: 23 + 10 = 33."],
    "TPR3_07": ["Сетка: 1, 5, 6/2, 8, 10/3, 11, ?", "Добавьте первые два столбца в каждую строку.", ["14", "13", "15", "33"], "1 столбик + 2 столбец = 3 столбик. 3 ряд: 3 + 11 = 14."],
    "TPR3_08": ["Что дальше? 1, 6, 15, 28, 45, ?", "Посмотрите на различия, затем на различия различий.", ["66", "60", "56", "72"], "Отличия 5, 9, 13, 17 (увеличение на 4). Следующая разница 21:45+21=66."],
    "TPR3_09": ["Что дальше? 100, 95, 85, 70, 50, ?", "Насколько уменьшается каждый шаг? Эта сумма растет.", ["25", "30", "20", "35"], "Разности имеют -5, -10, -15, -20, поэтому -25 следует: 50 - 25 = 25."],
    "TPR3_10": ["Сетка: 3, 4, 12/5, 6, 30/7, 8, ?", "Как столбец 3 связан с столбцами 1 и 2?", ["56", "15", "48", "60"], "Столбец 1 × Столбец 2 = Столбец 3. Ряд 3: 7 × 8 = 56."],
    "TPR3_11": ["Что дальше? 3, 8, 15, 24, 35, ?", "Попробуйте выразить каждый член как n² минус что-то.", ["48", "44", "50", "42"], "Каждый член равен n² − 1: 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35, 7²−1=48."],
    "TPR3_12": ["Сетка: 2, 10, 5/3, 18, 6/4, 28, ?", "Как столбец 3 связан с другими столбцами?", ["7", "8", "12", "32"], "Столбец 2 ÷ Столбец 1 = Столбец 3. Ряд 3: 28 ÷ 4 = 7."],
    "TPR3_13": ["Что дальше? 5, 6, 8, 11, 15, 20, ?", "На каждом шаге различия между членами увеличиваются на 1.", ["26", "25", "27", "24"], "Различия равны 1, 2, 3, 4, 5, поэтому следующая разница равна 6: 20 + 6 = 26."],
    "TPR3_14": ["Что дальше? 2, 5, 10, 17, 26, ?", "Попробуйте формулу n² + 1 для последовательных значений n.", ["37", "35", "38", "36"], "Каждый член равен n² + 1: 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TPR3_15": ["Сетка: 2, 5, 7/3, 4, 7/8, 3, ?", "Добавьте первые два столбца в каждую строку.", ["11", "24", "5", "10"], "1 столбик + 2 столбец = 3 столбик. 3 ряд: 8 + 3 = 11."],
    "TPR3_16": ["Сетка: 6, 2, 3/15, 3, 5/24, 4, ?", "Разделите столбец 1 на столбец 2.", ["6", "8", "7", "28"], "Столбец 1 ÷ Столбец 2 = Столбец 3. Ряд 3: 24 ÷ 4 = 6."],
    "TPR3_17": ["Что дальше? 2, 8, 32, 128, ?", "Каждое слагаемое умножается на одно и то же число.", ["512", "256", "384", "640"], "Каждый член умножается на 4. После 128 следующий член равен 128 × 4 = 512."],
    "TPR3_18": ["Что дальше? 10, 12, 16, 22, 30, ?", "Проверьте, как меняется разрыв между терминами.", ["40", "38", "42", "36"], "Различия равны 2, 4, 6, 8, поэтому следующая разница равна 10: 30 + 10 = 40."],
    "TPR3_19": ["Что дальше? 4, 7, 12, 19, 28, ?", "На каждом шаге различия между членами увеличиваются на 2.", ["39", "37", "41", "35"], "Различия равны 3, 5, 7, 9, поэтому следующая разница равна 11: 28 + 11 = 39."],
    "TPR3_20": ["Сетка: 4, 2, 8/9, 3, 27/16, 4, ?", "Столбец 1 — квадрат n, столбец 2 — n, столбец 3 — куб n.", ["64", "48", "32", "20"], "Столбец 1 = n², столбец 2 = n, столбец 3 = n³. Третья строка: 4² = 16, 4, 4³ = 64."],
    "TPR4_01": ["Что дальше? 1, 16, 81, 256, ?", "Каждый член представляет собой четвертую степень.", ["625", "512", "500", "1024"], "Строка — 1⁴, 2⁴, 3⁴, 4⁴, поэтому следует 5⁴ = 625."],
    "TPR4_02": ["Сетка: 5, 25, 125/6, 36, 216/7, 49, ?", "В каждой строке указано n, n², n³.", ["343", "294", "350", "336"], "3 ряд: 7¹ = 7, 7² = 49, 7³ = 343."],
    "TPR4_03": ["Что дальше? 2, 8, 26, 80, 242, ?", "Попробуйте выразить каждое слагаемое в виде степени 3 минус 1.", ["728", "486", "720", "500"], "Каждый член равен 3ⁿ − 1: 3¹−1=2, 3²−1=8, 3³−1=26, 3⁴−1=80, 3⁵−1=242, 3⁶−1=728."],
    "TPR4_04": ["Что дальше? 1, 4, 13, 40, 121, ?", "Каждое слагаемое утраивается, а затем увеличивается на 1.", ["364", "242", "360", "400"], "Каждый член = предыдущий × 3 + 1: 1→4, 4→13, 13→40, 40→121, 121→364."],
    "TPR4_05": ["Что дальше? 2, 3, 5, 8, 13, ?", "Посмотрите на различия — они следуют знакомой схеме.", ["21", "18", "20", "16"], "Различия равны 1, 2, 3, 5, 8 — каждая разница равна сумме двух предыдущих. Следующая разница равна 8, значит 13 + 8 = 21."],
    "TPR4_06": ["Что дальше? 1, 4, 10, 20, 35, ?", "Посмотрите на различия второго порядка — они увеличиваются на 1.", ["56", "50", "48", "55"], "Первые разности: 3, 6, 10, 15. Вторые разности: 3, 4, 5 → следующая — 6. Следующая первая разность: 21. Ответ: 35 + 21 = 56."],
    "TPR4_07": ["Что дальше? 1, 3, 2, 6, 4, 12, 8, ?", "Разбейте последовательность на члены с нечетными и четными позициями.", ["24", "16", "10", "20"], "Нечетные позиции: 1, 2, 4, 8 (×2). Четные позиции: 3, 6, 12, 24 (×2). Следующий четный член равен 24."],
    "TPR4_08": ["Сетка: 2, 3, 11/4, 5, 29/6, 7, ?", "Попробуйте (столбец 1 + 1) × (столбец 2 + 1) − 1.", ["55", "42", "48", "53"], "Столбец 3 = (столбец 1 + 1) × (столбец 2 + 1) − 1. Строка 3: 7 × 8 − 1 = 55."],
    "TPR4_09": ["Что дальше? 256, 128, 64, 32, 16, ?", "Каждый термин делится пополам.", ["8", "4", "12", "10"], "Каждый член делится на 2. После 16 следующий член равен 16 ÷ 2 = 8."],
    "TPR4_10": ["Сетка: 1, 2, 3, 6/2, 3, 5, 30/3, 4, 7, ?", "Как последняя колонка связана с первыми тремя?", ["84", "14", "21", "72"], "Столбец 4 = Столбец 1 × Столбец 2 × Столбец 3. Строка 3: 3 × 4 × 7 = 84."],
    "TPR4_11": ["Что дальше? 2, 6, 18, 54, ?", "Каждое слагаемое умножается на одно и то же число.", ["162", "108", "144", "216"], "Каждый член умножается на 3. После 54 следующий член равен 54 × 3 = 162."],
    "TPR4_12": ["Что дальше? 1, 5, 14, 30, 55, ?", "Различия между терминами имеют квадраты.", ["91", "80", "85", "90"], "Различия имеют 4, 9, 16, 25 (то есть 2², 3², 4², 5²). Следующая разница 6² = 36: 55 + 36 = 91."],
    "TPR4_13": ["Что дальше? 1000, 500, 250, 125, ?", "Каждый термин делится пополам.", ["62.5", "60", "75", "100"], "Каждый член делится на 2. После 125 следующий член равен 125 ÷ 2 = 62,5."],
    "TPR4_14": ["Сетка: 10, 3, 7/20, 8, 12/30, 11, ?", "Как столбцы связаны арифметически?", ["19", "20", "21", "41"], "Столбец 1 – Столбец 2 = Столбец 3. Ряд 3: 30 – 11 = 19."],
    "TPR4_15": ["Что дальше? 4, 5, 9, 14, 23, 37, ?", "Каждое слагаемое представляет собой сумму двух предыдущих слагаемых.", ["60", "51", "56", "74"], "Как Фибоначчи: каждый член = сумма двух предыдущих. 23 + 37 = 60."],
    "TPR4_16": ["Сетка: 2, 8, 3/3, 27, 8/4, 64, ?", "Столбец 2 представляет собой степень столбца 1. Какому образцу соответствует столбец 3?", ["15", "16", "12", "20"], "Столбец 2 = Столбец 1³. Столбец 3 = Столбец 1² − 1: 2²−1=3, 3²−1=8, 4²−1=15."],
    "TPR4_17": ["Что дальше? 1, 5, 21, 85, ?", "Попробуйте умножить каждое слагаемое на 4 и прибавить 1.", ["341", "256", "340", "345"], "Каждый член = предыдущий × 4 + 1: 1→5, 5→21, 21→85, 85→341."],
    "TPR4_18": ["Что дальше? 1, 2, 5, 12, 29, ?", "Каждый термин использует два предыдущих термина с множителем.", ["70", "58", "65", "72"], "Правило: a(n) = 2×a(n−1) + a(n−2). Проверка: 2×2+1=5, 2×5+2=12, 2×12+5=29, 2×29+12=70."],
    "TPR4_19": ["Сетка: 3, 2, 11/4, 3, 19/5, 4, ?", "Попробуйте возвести в квадрат столбец 1 и добавить столбец 2.", ["29", "20", "25", "30"], "Столбец 3 = Столбец 1² + Столбец 2. Ряд 3: 5² + 4 = 25 + 4 = 29."],
    "TPR4_20": ["Сетка: 4, 3, 13/5, 2, 23/6, 1, ?", "Попробуйте возвести в квадрат столбец 1 и вычесть столбец 2.", ["35", "30", "36", "42"], "Столбец 3 = Столбец 1² − Столбец 2. Строка 3: 6² − 1 = 36 − 1 = 35."],
    "TPR5_01": ["Что следует дальше в последовательности простых чисел? 23, 29, 31, 37, 41, ?", "Назовите простые числа после 41.", ["43", "42", "45", "47"], "Строка перечисляет последовательные простые числа. Следующее простое число после 41 — 43."],
    "TPR5_02": ["Что дальше? 2, 1, 3, 4, 7, 11, 18, ?", "Каждое слагаемое представляет собой сумму двух предыдущих слагаемых.", ["29", "25", "27", "36"], "Это последовательность типа Лукаса: каждый член = сумма двух предыдущих. 11+18=29."],
    "TPR5_03": ["Сетка: 2, 8, 32/3, 27, 243/5, 125, ?", "В каждом столбце используется нечетная степень первого числа.", ["3125", "625", "1250", "1500"], "Шаблон рядов: n¹, n³, n⁵. 3 ряд: 5¹=5, 5³=125, 5⁵=3125."],
    "TPR5_04": ["Что дальше? 4, 6, 10, 14, 22, 26, ?", "Каждый член — удвоенное простое число. Какое простое дальше?", ["34", "30", "32", "38"], "2×2, 2×3, 2×5, 2×7, 2×11, 2×13, далее 2×17 = 34."],
    "TPR5_05": ["Что дальше? 0, 0, 1, 1, 2, 4, 7, 13, ?", "Каждое слагаемое представляет собой сумму трёх предыдущих слагаемых.", ["24", "20", "26", "19"], "Это последовательность Трибоначчи: каждый член = сумма трех предыдущих. 4 + 7 + 13 = 24."],
    "TPR5_06": ["Что дальше? 2, 12, 36, 80, 150, ?", "Попробуйте выразить каждый член как n²(n + 1).", ["252", "210", "240", "260"], "Каждый член равен n²(n+1): 1²×2=2, 2²×3=12, 3²×4=36, 4²×5=80, 5²×6=150, 6²×7=252."],
    "TPR5_07": ["Сетка: 1, 2, 5/2, 3, 13/4, 5, ?", "Попробуйте возвести в квадрат каждый из первых двух столбцов и сложить.", ["41", "20", "45", "36"], "Столбец 3 = Столбец 1² + Столбец 2². 3 ряд: 4²+5²=16+25=41."],
    "TPR5_08": ["Что дальше? 2, 8, 18, 32, 50, ?", "Попробуйте выразить каждый член как 2n² для последовательных значений n.", ["72", "60", "68", "80"], "Каждый член равен 2n²: 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TPR5_09": ["Что дальше? 2, 4, 16, 256, ?", "Каждое слагаемое представляет собой квадрат предыдущего слагаемого.", ["65536", "512", "1024", "4096"], "Каждый термин = предыдущий². 2²=4, 4²=16, 16²=256, 256²=65536."],
    "TPR5_10": ["Что дальше? 47, 43, 41, 37, 31, 29, ?", "Это простые числа в порядке убывания.", ["23", "27", "25", "19"], "Строка перечисляет последовательные простые числа в порядке убывания. После 29 следующее наименьшее простое число — 23."],
    "TPR5_11": ["Сетка: 2, 3, 7/4, 5, 21/6, 7, ?", "Умножьте первые два столбца и откорректируйте их на 1.", ["43", "42", "44", "40"], "Столбец 3 = Столбец 1 × Столбец 2 + 1. Ряд 3: 6 × 7 + 1 = 43."],
    "TPR5_12": ["Что дальше? 1, 5, 12, 22, 35, ?", "Это пятиугольные числа: n(3n − 1)/2.", ["51", "48", "50", "55"], "Пятиугольные числа: n(3n−1)/2. Для n=6: 6×17/2 = 51."],
    "TPR5_13": ["Что дальше? 2, 6, 30, 210, ?", "Каждое слагаемое умножается на следующее простое число.", ["2310", "1470", "1260", "1890"], "2×3=6, 6×5=30, 30×7=210, 210×11=2310. Каждый шаг умножается на следующее простое число."],
    "TPR5_14": ["Сетка: 4, 16, 64/6, 36, 216/8, 64, ?", "В каждой строке указаны степени первого числа.", ["512", "256", "480", "128"], "Шаблон рядов: n¹, n², n³. 3 ряд: 8, 64, 512."],
    "TPR5_15": ["Что дальше? 1, 3, 11, 43, ?", "Каждое слагаемое умножается на 4 и уменьшается на 1.", ["171", "170", "172", "160"], "Каждый член = предыдущий × 4 - 1: 1→3, 3→11, 11→43, 43→171."],
    "TPR5_16": ["Что дальше? 59, 53, 47, 43, 41, 37, ?", "Сначала они перечислены в порядке убывания.", ["31", "33", "29", "35"], "В последовательности перечислены последовательные простые числа в обратном порядке. После 37 следующее наименьшее простое число — 31."],
    "TPR5_17": ["Что дальше? 27, 125, 343, 729, ?", "Каждый терм представляет собой куб. Чьи числа?", ["1331", "1000", "1200", "1500"], "Это кубы последовательных нечетных чисел: 3³=27, 5³=125, 7³=343, 9³=729, 11³=1331."],
    "TPR5_18": ["Сетка: 3, 2, 18/4, 3, 48/5, 4, ?", "Попробуйте возвести в квадрат столбец 1 и умножить на столбец 2.", ["100", "80", "60", "125"], "Столбец 3 = Столбец 1² × Столбец 2. Строка 3: 5² × 4 = 25 × 4 = 100."],
    "TPR5_19": ["Что дальше? 2, 3, 6, 7, 14, 15, ?", "Последовательность чередуется между двумя операциями.", ["30", "16", "28", "22"], "В шаблоне чередуются +1 и ×2: 2+1=3, 3×2=6, 6+1=7, 7×2=14, 14+1=15, 15×2=30."],
    "TPR5_20": ["Что дальше? 1, 9, 36, 100, 225, ?", "Каждый член — квадрат суммы 1, 1+2, 1+2+3, …", ["441", "400", "484", "500"], "1², 3², 6², 10², 15², далее 21² = 441 (треугольные числа в квадрате)."],
    "TNR1_01": ["Что идет дальше в строке: 7, 8, 9, 10, 11, ?", "Посмотрите на разницу между каждой парой последовательных терминов.", ["12", "13", "10", "14"], "Каждый член увеличивается на 1. Следующий член равен 11 + 1 = 12."],
    "TNR1_02": ["Что идет дальше в строке: 3, 5, 7, 9, 11, ?", "Вычтите каждое слагаемое из следующего.", ["13", "12", "14", "15"], "Каждый член увеличивается на 2. Следующий член равен 11 + 2 = 13."],
    "TNR1_03": ["Что идет дальше в строке: 10, 13, 16, 19, 22, ?", "Найдите постоянную разность между соседними членами.", ["25", "24", "26", "23"], "Каждый член увеличивается на 3. Следующий член равен 22 + 3 = 25."],
    "TNR1_04": ["Что идет дальше в строке: 1, 5, 9, 13, 17, ?", "На сколько каждый член увеличивается по сравнению с предыдущим?", ["21", "20", "22", "19"], "Каждый член увеличивается на 4. Следующий член равен 17 + 4 = 21."],
    "TNR1_05": ["Что идет дальше в строке: 2, 7, 12, 17, 22, ?", "Рассчитайте шаг между последовательными членами.", ["27", "25", "28", "26"], "Каждый член увеличивается на 5. Следующий член равен 22 + 5 = 27."],
    "TNR1_06": ["Что идет дальше в строке: 4, 10, 16, 22, 28, ?", "Что добавляется каждый раз?", ["34", "32", "36", "30"], "Каждый член увеличивается на 6. Следующий член равен 28 + 6 = 34."],
    "TNR1_07": ["Что идет дальше в строке: 3, 10, 17, 24, 31, ?", "Найдите константу, добавленную к каждому члену.", ["38", "35", "39", "37"], "Каждый член увеличивается на 7. Следующий член равен 31 + 7 = 38."],
    "TNR1_08": ["Что идет дальше в строке: 5, 13, 21, 29, 37, ?", "Вычтите первое слагаемое из второго, чтобы найти размер шага.", ["45", "44", "46", "43"], "Каждый член увеличивается на 8. Следующий член равен 37 + 8 = 45."],
    "TNR1_09": ["Что идет дальше в строке: 2, 11, 20, 29, 38, ?", "Какое число добавляется к каждому шагу?", ["47", "45", "48", "46"], "Каждый член увеличивается на 9. Следующий член равен 38 + 9 = 47."],
    "TNR1_10": ["Что идет дальше в строке: 6, 16, 26, 36, 46, ?", "Посмотрите на интервал между любыми двумя последовательными терминами.", ["56", "54", "58", "52"], "Каждый член увеличивается на 10. Следующий член равен 46 + 10 = 56."],
    "TNR1_11": ["Что идет дальше в строке: 20, 19, 18, 17, 16, ?", "Последовательность убывает. Сколько на каждом этапе?", ["15", "14", "17", "13"], "Каждый член уменьшается на 1. Следующий член равен 16 − 1 = 15."],
    "TNR1_12": ["Что идет дальше в строке: 30, 28, 26, 24, 22, ?", "Вычтите каждое слагаемое из предыдущего.", ["20", "21", "18", "19"], "Каждое слагаемое уменьшается на 2. Следующее слагаемое равно 22 − 2 = 20."],
    "TNR1_13": ["Что идет дальше в строке: 40, 37, 34, 31, 28, ?", "Последовательность убывает. Найдите постоянный шаг.", ["25", "26", "24", "27"], "Каждое слагаемое уменьшается на 3. Следующее слагаемое равно 28 − 3 = 25."],
    "TNR1_14": ["Что идет дальше в строке: 50, 46, 42, 38, 34, ?", "Насколько уменьшается каждый раз?", ["30", "32", "28", "31"], "Каждое слагаемое уменьшается на 4. Следующее слагаемое равно 34 − 4 = 30."],
    "TNR1_15": ["Что идет дальше в строке: 60, 55, 50, 45, 40, ?", "Найдите постоянную разность между соседними членами.", ["35", "30", "38", "33"], "Каждый член уменьшается на 5. Следующий член равен 40 − 5 = 35."],
    "TNR1_16": ["Что идет дальше в строке: 5, 16, 27, 38, 49, ?", "Вычислите разницу между первыми двумя членами и проверьте, осталась ли она прежней.", ["60", "58", "61", "55"], "Каждый член увеличивается на 11. Следующий член равен 49 + 11 = 60."],
    "TNR1_17": ["Что идет дальше в строке: 3, 15, 27, 39, 51, ?", "Какая константа добавляется на каждом шаге?", ["63", "60", "64", "62"], "Каждый член увеличивается на 12. Следующий член равен 51 + 12 = 63."],
    "TNR1_18": ["Что идет дальше в строке: 10, 25, 40, 55, 70, ?", "Найдите постоянный шаг между соседними членами.", ["85", "80", "90", "75"], "Каждый член увеличивается на 15. Следующий член равен 70 + 15 = 85."],
    "TNR1_19": ["Что идет дальше в строке: 5, 25, 45, 65, 85, ?", "Рассчитайте размер шага от любого члена к следующему.", ["105", "100", "110", "95"], "Каждый член увеличивается на 20. Следующий член равен 85 + 20 = 105."],
    "TNR1_20": ["Что идет дальше в строке: 42, 36, 30, 24, 18, ?", "Последовательность убывает. Что вычитается каждый раз?", ["12", "14", "10", "16"], "Каждое слагаемое уменьшается на 6. Следующее слагаемое равно 18 − 6 = 12."],
    "TNR2_01": ["Что идет дальше в строке: 5, 10, 20, 40, 80, ?", "Попробуйте разделить каждое слагаемое на предыдущее.", ["160", "120", "140", "100"], "Каждое слагаемое умножается на 2. Следующее слагаемое равно 80 × 2 = 160."],
    "TNR2_02": ["Что идет дальше в строке: 2, 6, 18, 54, 162, ?", "Каково соотношение соседних членов?", ["486", "324", "480", "648"], "Каждое слагаемое умножается на 3. Следующее слагаемое равно 162 × 3 = 486."],
    "TNR2_03": ["Что идет дальше в строке: 1, 4, 16, 64, 256, ?", "Разделите второе слагаемое на первое, чтобы найти множитель.", ["1024", "512", "768", "1280"], "Каждое слагаемое умножается на 4. Следующее слагаемое равно 256 × 4 = 1024."],
    "TNR2_04": ["Что идет дальше в строке: 2, 10, 50, 250, 1250, ?", "Посмотрите на соотношение последовательных членов.", ["6250", "5000", "6000", "7500"], "Каждое слагаемое умножается на 5. Следующее слагаемое равно 1250 × 5 = 6250."],
    "TNR2_05": ["Что идет дальше в строке: 3, 30, 300, 3000, 30000, ?", "Каждый член получает дополнительный ноль. Какой множитель это делает?", ["300000", "60000", "200000", "330000"], "Каждое слагаемое умножается на 10. Следующее слагаемое равно 30000×10 = 300000."],
    "TNR2_06": ["Что идет дальше в строке: 640, 320, 160, 80, 40, ?", "Строка делится пополам. Какая операция применяется на каждом этапе?", ["20", "10", "30", "25"], "Каждый член делится на 2. Следующий член равен 40 ÷ 2 = 20."],
    "TNR2_07": ["Что идет дальше в строке: 729, 243, 81, 27, 9, ?", "Каждый член делите на 3.", ["3", "6", "1", "4"], "Каждый член делится на 3. Следующий: 9 ÷ 3 = 3."],
    "TNR2_08": ["Что идет дальше в строке: 192, 96, 48, 24, 12, ?", "Какую часть предыдущего члена дает текущий срок?", ["6", "4", "8", "3"], "Каждый член делится на 2. Следующий член равен 12 ÷ 2 = 6."],
    "TNR2_09": ["Что идет дальше в строке: 3, 4, 7, 11, 18, ?", "Попробуйте добавить два последовательных термина.", ["29", "25", "27", "30"], "Каждое слагаемое представляет собой сумму двух предыдущих слагаемых: 11 + 18 = 29."],
    "TNR2_10": ["Что идет дальше в строке: 2, 5, 7, 12, 19, ?", "Посмотрите, как каждый термин соотносится с двумя предыдущими.", ["31", "26", "28", "33"], "Каждое слагаемое представляет собой сумму двух предыдущих слагаемых: 12 + 19 = 31."],
    "TNR2_11": ["Что идет дальше в строке: 4, 9, 19, 39, 79, ?", "Попробуйте удвоить термин, а затем скорректировать его на небольшое число, чтобы получить следующий.", ["159", "158", "160", "149"], "Каждый член подчиняется правилу: предыдущий × 2 + 1. Следующий член — 79 × 2 + 1 = 159."],
    "TNR2_12": ["Что идет дальше в строке: 4, 12, 36, 108, 324, ?", "Разделите каждый член на предыдущий, чтобы найти постоянное соотношение.", ["972", "648", "1296", "900"], "Каждое слагаемое умножается на 3. Следующее слагаемое равно 324 × 3 = 972."],
    "TNR2_13": ["Что идет дальше в строке: 7, 14, 28, 56, 112, ?", "Что произойдет, если разделить каждое слагаемое на предшествующее?", ["224", "168", "220", "228"], "Каждое слагаемое умножается на 2. Следующее слагаемое равно 112 × 2 = 224."],
    "TNR2_14": ["Что идет дальше в строке: 1, 3, 4, 7, 11, ?", "Проверьте, является ли каждое слагаемое суммой двух предыдущих.", ["18", "15", "16", "20"], "Каждое слагаемое представляет собой сумму двух предыдущих слагаемых: 7 + 11 = 18."],
    "TNR2_15": ["Что идет дальше в строке: 256, 128, 64, 32, 16, ?", "Все это степени двойки. Какой делитель соединяет каждую пару?", ["8", "4", "12", "10"], "Каждый член делится на 2. Следующий член равен 16 ÷ 2 = 8."],
    "TNR2_16": ["Что идет дальше в строке: 1, 5, 25, 125, 625, ?", "Найдите множитель, разделив любое слагаемое на предыдущее.", ["3125", "1250", "3000", "3750"], "Каждое слагаемое умножается на 5. Следующее слагаемое равно 625 × 5 = 3125."],
    "TNR2_17": ["Что идет дальше в строке: 3, 8, 18, 38, 78, ?", "Попробуйте удвоить предыдущий член и добавить небольшую константу.", ["158", "156", "160", "148"], "Каждый член подчиняется правилу: предыдущий × 2 + 2. Следующий член — 78 × 2 + 2 = 158."],
    "TNR2_18": ["Что идет дальше в строке: 1, 4, 5, 9, 14, ?", "Посмотрите, дает ли сумма двух последовательных членов следующее.", ["23", "19", "21", "25"], "Каждое слагаемое представляет собой сумму двух предыдущих слагаемых: 9 + 14 = 23."],
    "TNR2_19": ["Что идет дальше в строке: 2187, 729, 243, 81, 27, ?", "Каждое слагаемое является частью предыдущего. Какой делитель используется?", ["9", "3", "18", "12"], "Каждый член делится на 3. Следующий член равен 27 ÷ 3 = 9."],
    "TNR2_20": ["Что идет дальше в строке: 2, 8, 32, 128, 512, ?", "Разделите последовательные члены, чтобы найти постоянный множитель.", ["2048", "1024", "2560", "1536"], "Каждое слагаемое умножается на 4. Следующее слагаемое равно 512 × 4 = 2048."],
    "TNR3_01": ["Что идет дальше в строке: 36, 49, 64, 81, 100, ?", "Попробуйте извлечь квадратный корень из каждого члена.", ["121", "110", "120", "125"], "Существуют последовательные идеальные квадраты: 6²=36, 7²=49, 8²=64, 9²=81, 10²=100, 11²=121."],
    "TNR3_02": ["Что идет дальше в строке: 100, 121, 144, 169, 196, ?", "Каждый член — квадрат натурального числа.", ["225", "220", "230", "216"], "Подряд идут квадраты: 10², 11², 12², 13², 14², далее 15² = 225."],
    "TNR3_03": ["Что идет дальше в строке: 125, 216, 343, 512, 729, ?", "Попробуйте извлечь кубический корень из каждого члена.", ["1000", "900", "1024", "972"], "Это последовательные совершенные кубы: 5³=125, 6³=216, 7³=343, 8³=512, 9³=729, 10³=1000."],
    "TNR3_04": ["Что идет дальше в строке: 343, 512, 729, 1000, 1331, ?", "Это кубы последовательных целых чисел. Какие целые числа?", ["1728", "1500", "1700", "2000"], "Это последовательные совершенные кубы: 7³=343, 8³=512, 9³=729, 10³=1000, 11³=1331, 12³=1728."],
    "TNR3_05": ["Что идет дальше в строке: 10, 12, 16, 22, 30, ?", "Вычислите различия между терминами. Формируют ли эти различия закономерность?", ["40", "38", "42", "36"], "Различия составляют 2, 4, 6, 8 — увеличиваются на 2 на каждом шаге. Следующая разница — 10, значит 30 + 10 = 40."],
    "TNR3_06": ["Что идет дальше в строке: 7, 10, 16, 25, 37, ?", "Найдите различия между терминами, а затем найдите закономерность в этих различиях.", ["52", "49", "55", "46"], "Различия составляют 3, 6, 9, 12 — увеличиваются на 3 на каждом шаге. Следующая разница — 15, значит 37 + 15 = 52."],
    "TNR3_07": ["Что идет дальше в строке: 5, 6, 9, 14, 21, ?", "Различия между терминами имеют последовательные нечетные числа.", ["30", "28", "32", "27"], "Различия составляют 1, 3, 5, 7 — последовательные нечетные числа. Следующая разница — 9, значит 21 + 9 = 30."],
    "TNR3_08": ["Что идет дальше в строке: 5, 7, 11, 13, 17, ?", "Вспомните числа, у которых ровно два делителя.", ["19", "18", "21", "20"], "Это последовательные простые числа, начиная с 5. Следующее простое число после 17 — 19."],
    "TNR3_09": ["Что идет дальше в строке: 11, 13, 17, 19, 23, ?", "Делятся ли эти числа только на 1 и на самих себя?", ["29", "27", "25", "31"], "Это последовательные простые числа, начиная с 11. Следующее простое число после 23 — 29."],
    "TNR3_10": ["Что идет дальше в строке: 4, 16, 36, 64, 100, ?", "Извлеките квадратный корень из каждого слагаемого. Что общего у этих цифр?", ["144", "128", "136", "148"], "Это квадраты последовательных четных чисел: 2²=4, 4²=16, 6²=36, 8²=64, 10²=100, 12²=144."],
    "TNR3_11": ["Что идет дальше в строке: 1, 9, 25, 49, 81, ?", "Извлеките квадратный корень из каждого слагаемого. Что это за числа?", ["121", "100", "110", "125"], "Это квадраты последовательных нечетных чисел: 1²=1, 3²=9, 5²=25, 7²=49, 9²=81, 11²=121."],
    "TNR3_12": ["Что идет дальше в строке: 2, 5, 10, 17, 26, ?", "Вычтите 1 из каждого члена. Результаты кажутся вам знакомыми?", ["37", "35", "36", "39"], "Каждый член равен n² + 1: 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TNR3_13": ["Что идет дальше в строке: 0, 3, 8, 15, 24, ?", "Добавьте 1 к каждому члену. Какая известная последовательность у вас получилась?", ["35", "33", "36", "30"], "Каждый член равен n² − 1: 1²−1=0, 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35."],
    "TNR3_14": ["Что идет дальше в строке: 5, 9, 17, 29, 45, ?", "Вычислите различия, а затем проверьте, регулярно ли эти различия увеличиваются.", ["65", "61", "69", "57"], "Различия составляют 4, 8, 12, 16 — увеличиваются на 4 на каждом шаге. Следующая разница — 20, значит 45 + 20 = 65."],
    "TNR3_15": ["Что идет дальше в строке: 2, 9, 28, 65, 126, ?", "Вычтите 1 из каждого члена. Какие цифры остались?", ["217", "215", "220", "210"], "Каждый член равен n³ + 1: 1³+1=2, 2³+1=9, 3³+1=28, 4³+1=65, 5³+1=126, 6³+1=217."],
    "TNR3_16": ["Что идет дальше в строке: 3, 8, 15, 24, 35, ?", "Попробуйте выразить каждый член как произведение двух чисел, расположенных рядом.", ["48", "46", "50", "44"], "Каждый член равен n(n + 2): 1×3=3, 2×4=8, 3×5=15, 4×6=24, 5×7=35, 6×8=48."],
    "TNR3_17": ["Что идет дальше в строке: 1, 5, 11, 19, 29, ?", "Различия между терминами увеличиваются на константу. Найдите эту константу.", ["41", "39", "43", "37"], "Различия составляют 4, 6, 8, 10 — увеличиваются на 2 на каждом шаге. Следующая разница — 12, значит 29 + 12 = 41."],
    "TNR3_18": ["Что идет дальше в строке: 2, 8, 18, 32, 50, ?", "Попробуйте разделить каждое слагаемое на 2. Результаты кажутся вам знакомыми?", ["72", "68", "74", "64"], "Каждый член равен 2n²: 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TNR3_19": ["Что идет дальше в строке: 4, 7, 12, 19, 28, ?", "Вычтите 3 из каждого члена. Какую последовательность вы узнали?", ["39", "37", "41", "36"], "Каждый член равен n² + 3: 1²+3=4, 2²+3=7, 3²+3=12, 4²+3=19, 5²+3=28, 6²+3=39."],
    "TNR3_20": ["Что идет дальше в строке: 4, 9, 19, 34, 54, ?", "Найдите различия, затем различия этих различий.", ["79", "74", "84", "69"], "Различия составляют 5, 10, 15, 20 — увеличиваются на 5 на каждом шаге. Следующая разница — 25, значит 54 + 25 = 79."],
    "TNR4_01": ["Что идет дальше в строке: 2, 3, 7, 25, 121, ?", "Вычтите 1 из каждого члена и посмотрите, узнаете ли вы эти числа.", ["721", "720", "625", "719"], "Каждый член равен n! + 1: 1!+1=2, 2!+1=3, 3!+1=7, 4!+1=25, 5!+1=121, 6!+1=721."],
    "TNR4_02": ["Что идет дальше в строке: 0, 1, 5, 23, 119, ?", "Добавьте 1 к каждому члену. Узнаете полученные цифры?", ["719", "720", "600", "721"], "Каждый член равен n! − 1: 1!−1=0, 2!−1=1, 3!−1=5, 4!−1=23, 5!−1=119, 6!−1=719."],
    "TNR4_03": ["Что идет дальше в строке: 15, 21, 28, 36, 45, ?", "Это треугольные числа. На каждом шаге различия между членами увеличиваются на 1.", ["55", "54", "56", "50"], "Это треугольные числа от T(5) до T(10). Различия равны 6, 7, 8, 9, поэтому следующая разница равна 10: 45 + 10 = 55."],
    "TNR4_04": ["Что идет дальше в строке: 36, 45, 55, 66, 78, ?", "Посчитайте различия. Каждый раз они увеличиваются на 1 — отличительная черта треугольных чисел.", ["91", "88", "90", "84"], "Это треугольные числа от T(8) до T(13). Различия составляют 9, 10, 11, 12, поэтому следующая разница равна 13: 78 + 13 = 91."],
    "TNR4_05": ["Что идет дальше в строке: 1, 5, 13, 29, 61, ?", "Попробуйте удвоить предыдущий член и добавить небольшую константу.", ["125", "122", "123", "127"], "Каждый член подчиняется правилу: предыдущий × 2 + 3. Следующий член — 61 × 2 + 3 = 125."],
    "TNR4_06": ["Что идет дальше в строке: 1, 2, 5, 14, 41, ?", "Попробуйте умножить предыдущий член на 3 и внести поправки.", ["122", "120", "123", "82"], "Каждый член следует правилу: предыдущий × 3 — 1. Следующий член — 41 × 3 — 1 = 122."],
    "TNR4_07": ["Что идет дальше в строке: 2, 9, 23, 51, 107, ?", "Удвойте предыдущий член и добавьте константу, чтобы получить следующий.", ["219", "214", "215", "221"], "Каждый член подчиняется правилу: предыдущий × 2 + 5. Следующий член — 107 × 2 + 5 = 219."],
    "TNR4_08": ["Что идет дальше в строке: 9, 25, 49, 121, 169, ?", "Возьмите квадратный корень из каждого члена и подумайте, что делает эти числа особенными.", ["289", "225", "256", "324"], "Это квадраты последовательных простых чисел: 3²=9, 5²=25, 7²=49, 11²=121, 13²=169, 17²=289."],
    "TNR4_09": ["Что идет дальше в строке: 10, 11, 15, 24, 40, ?", "Найдите различия между терминами. Являются ли эти различия известной строкой?", ["65", "56", "64", "60"], "Различия: 1, 4, 9, 16 — идеальные квадраты (1², 2², 3², 4²). Следующая разница 5²=25, то есть 40 + 25 = 65."],
    "TNR4_10": ["Что идет дальше в строке: 0, 1, 3, 9, 33, ?", "Посмотрите на разности между соседними членами — узнаёте ли вы закономерность?", ["153", "129", "150", "57"], "Разности 1, 2, 6, 24 — факториалы 1!, 2!, 3!, 4!. Следующая разность 5! = 120, значит 33 + 120 = 153."],
    "TNR4_11": ["Что идет дальше в строке: 2, 7, 22, 67, 202, ?", "Умножьте предыдущий член на число и добавьте константу.", ["607", "606", "605", "610"], "Каждый член подчиняется правилу: предыдущий × 3 + 1. Следующий член — 202 × 3 + 1 = 607."],
    "TNR4_12": ["Что идет дальше в строке: 20, 37, 71, 139, 275, ?", "Попробуйте удвоить предыдущий член и вычесть небольшую константу.", ["547", "550", "545", "553"], "Каждый член следует правилу: предыдущий × 2 — 3. Следующий член — 275 × 2 — 3 = 547."],
    "TNR4_13": ["Что идет дальше в строке: 1, 5, 14, 30, 55, ?", "Различия между терминами имеют квадраты. Суммируйте последовательные квадраты.", ["91", "85", "90", "80"], "Это совокупные суммы квадратов: 1, 1+4=5, 5+9=14, 14+16=30, 30+25=55, 55+36=91."],
    "TNR4_14": ["Что идет дальше в строке: 2, 4, 12, 48, 240, ?", "Попробуйте разделить каждое слагаемое на 2. Результаты похожи на факториалы?", ["1440", "1200", "1680", "960"], "Каждый член равен 2×n!: 2×1!=2, 2×2!=4, 2×3!=12, 2×4!=48, 2×5!=240, 2×6!=1440."],
    "TNR4_15": ["Что идет дальше в строке: 6, 13, 27, 55, 111, ?", "Удвойте предыдущий член и добавьте константу на каждом шаге.", ["223", "222", "220", "225"], "Каждый член подчиняется правилу: предыдущий × 2 + 1. Следующий член — 111 × 2 + 1 = 223."],
    "TNR4_16": ["Что идет дальше в строке: 10, 11, 14, 20, 30, ?", "Различия между терминами имеют треугольные цифры: 1, 3, 6, 10,…", ["45", "40", "42", "50"], "Отличия: 1, 3, 6, 10 — треугольные числа. Следующее треугольное число — 15, значит 30 + 15 = 45."],
    "TNR4_17": ["Что идет дальше в строке: 12, 20, 30, 42, 56, ?", "Каждый член — произведение двух последовательных натуральных чисел.", ["72", "68", "70", "64"], "n(n+1): 3×4=12, 4×5=20, …, 7×8=56, далее 8×9=72."],
    "TNR4_18": ["Что идет дальше в строке: 1, 9, 36, 100, 225, ?", "Квадраты треугольных чисел — то же самое, что суммы первых k кубов.", ["441", "400", "440", "450"], "1³, 1³+2³, … нарастающей суммой: после 225 идёт +6³, итого 441."],
    "TNR4_19": ["Что идет дальше в строке: 3, 7, 19, 55, 163, ?", "Умножьте предыдущий член на число и вычтите константу.", ["487", "489", "485", "492"], "Каждый член следует правилу: предыдущий × 3 — 2. Следующий член — 163 × 3 — 2 = 487."],
    "TNR4_20": ["Что идет дальше в строке: 12, 23, 45, 89, 177, ?", "Удвойте предыдущий член и внесите небольшую корректировку.", ["353", "354", "355", "350"], "Каждый член следует правилу: предыдущий × 2 — 1. Следующий член — 177 × 2 — 1 = 353."],
    "TNR5_01": ["Что идет дальше в строке: 1, 2, 9, 64, 625, ?", "Подумайте, до какой силы поднята база каждой позиции.", ["7776", "7774", "7200", "3125"], "Каждый член равен n, возведенному в степень (n−1): 1⁰=1, 2¹=2, 3²=9, 4³=64, 5⁴=625, 6⁵=7776."],
    "TNR5_02": ["Что идет дальше в строке: 2, 10, 30, 68, 130, ?", "Представьте каждый член как n³ + n.", ["222", "220", "218", "216"], "n³ + n: 1+1=2, 8+2=10, 27+3=30, 64+4=68, 125+5=130, 216+6=222."],
    "TNR5_03": ["Что идет дальше в строке: 1, 1, 2, 5, 14, ?", "Это каталонские цифры. Каждое C(n) = C(0)C(n−1) + C(1)C(n−2) + … + C(n−1)C(0).", ["42", "28", "35", "48"], "Это каталонские числа: C(0)=1, C(1)=1, C(2)=2, C(3)=5, C(4)=14, C(5)=42."],
    "TNR5_04": ["Что идет дальше в строке: 1, 5, 12, 22, 35, ?", "Отличия: 4, 7, 10, 13 — арифметическая последовательность с шагом 3.", ["51", "48", "50", "55"], "Это пятиугольные числа: n(3n−1)/2. Для n=6: 6×17/2 = 51."],
    "TNR5_05": ["Что идет дальше в строке: 2, 5, 13, 35, 97, ?", "Попробуйте выразить каждый член как сумму двух показательных выражений.", ["275", "265", "270", "280"], "Каждый член равен 2ⁿ + 3ⁿ (начиная с n=0): 1+1=2, 2+3=5, 4+9=13, 8+27=35, 16+81=97, 32+243=275."],
    "TNR5_06": ["Что идет дальше в строке: 1, 5, 17, 53, 161, ?", "Умножьте предыдущий член на 3 и добавьте небольшую константу.", ["485", "483", "322", "487"], "Каждый член подчиняется правилу: предыдущий × 3 + 2. Следующий член — 161 × 3 + 2 = 485."],
    "TNR5_07": ["Что идет дальше в строке: 1, 2, 5, 12, 27, ?", "Подумайте о степени двойки, а затем вычтите что-нибудь, что зависит от позиции.", ["58", "54", "56", "60"], "Каждый член равен 2ⁿ − n: 2¹−1=1, 2²−2=2, 2³−3=5, 2⁴−4=12, 2⁵−5=27, 2⁶−6=58."],
    "TNR5_08": ["Что идет дальше в строке: 2, 12, 36, 80, 150, ?", "Попробуйте разложить каждый член на n² раз.", ["252", "240", "250", "260"], "Каждый член равен n²(n+1): 1×2=2, 4×3=12, 9×4=36, 16×5=80, 25×6=150, 36×7=252."],
    "TNR5_09": ["Что идет дальше в строке: 1, 6, 15, 28, 45, ?", "Отличия 5, 9, 13, 17 — увеличиваются на 4. Это шестиугольные числа.", ["66", "60", "63", "70"], "Это шестиугольные числа: n(2n−1). Для n=6: 6×11 = 66."],
    "TNR5_10": ["Что идет дальше в строке: 2, 6, 15, 40, 145, ?", "Попробуйте разделить каждый член на факториал и квадратную часть.", ["756", "750", "745", "760"], "Каждый член равен n! + n²: 1!+1=2, 2!+4=6, 3!+9=15, 4!+16=40, 5!+25=145, 6!+36=756."],
    "TNR5_11": ["Что идет дальше в строке: 2, 4, 7, 14, 17, ?", "Операции чередуются между двумя разными правилами на нечетных и четных шагах.", ["34", "20", "31", "37"], "Шаблон чередуется: ×2, +3, ×2, +3, ×2. Итак, 17 × 2 = 34."],
    "TNR5_12": ["Что идет дальше в строке: 1, 5, 19, 65, 211, ?", "Выразите каждый член как разницу двух экспоненциальных значений.", ["665", "660", "633", "670"], "Каждый член равен 3ⁿ − 2ⁿ: 3−2=1, 9−4=5, 27−8=19, 81−16=65, 243−32=211, 729−64=665."],
    "TNR5_13": ["Что идет дальше в строке: 1, 4, 11, 29, 76, ?", "Каждый термин зависит от двух предшествующих ему терминов. Попробуйте линейную комбинацию.", ["199", "197", "200", "228"], "Правило такое: a(n) = 3×a(n−1) − a(n−2): 3×29−11=76, 3×76−29=199."],
    "TNR5_14": ["Что идет дальше в строке: 20, 22, 26, 34, 50, ?", "Различия составляют 2, 4, 8, 16 — степени двойки.", ["82", "66", "80", "84"], "Разности представляют собой степени 2: 2, 4, 8, 16. Следующая разность — 32, поэтому 50 + 32 = 82."],
    "TNR5_15": ["Что идет дальше в строке: 1, 4, 10, 20, 35, ?", "Это тетраэдрические числа — суммы последовательных треугольных чисел.", ["56", "50", "55", "60"], "Тетраэдрические числа: n(n+1)(n+2)/6. Для n=6: 6×7×8/6 = 56."],
    "TNR5_16": ["Что идет дальше в строке: 1, 13, 37, 73, 121, ?", "Разности составляют 12, 24, 36, 48 — кратны 12.", ["181", "169", "175", "193"], "Это звездные числа: 6n(n−1)+1. Для n=6: 6×30+1 = 181."],
    "TNR5_17": ["Что идет дальше в строке: 1, 7, 19, 37, 61, ?", "Разности составляют 6, 12, 18, 24 — кратны 6.", ["91", "85", "90", "97"], "Это центрированные шестиугольные числа: 3n(n−1)+1. Для n=6: 3×30+1 = 91."],
    "TNR5_18": ["Что идет дальше в строке: 3, 8, 17, 32, 57, ?", "Попробуйте выразить каждый член как сумму квадрата и степени 2.", ["100", "96", "98", "105"], "Каждый член равен n² + 2ⁿ: 1+2=3, 4+4=8, 9+8=17, 16+16=32, 25+32=57, 36+64=100."],
    "TNR5_19": ["Что идет дальше в строке: 1, 4, 8, 11, 22, ?", "Две разные операции чередуются. Один добавляет, другой умножает.", ["25", "44", "24", "26"], "Шаблон чередуется: +3, ×2, +3, ×2, +3. Итак, 22+3=25."],
    "TNR5_20": ["Что идет дальше в строке: 1, 1, 3, 5, 11, ?", "Каждый термин использует оба предыдущих термина с разными весами.", ["21", "16", "22", "19"], "Правило таково: a(n) = a(n−1) + 2×a(n−2): 5 + 2×3 = 11, 11 + 2×5 = 21."],
    "TLR1_01": ["Все врачи — профессионалы. Доктор Адамс — врач. Какой вывод вы можете сделать?", "Если все X — это Y, а Z — X, то Z — тоже Y.", ["Доктор Адамс — профессионал", "Доктор Адамс не профессионал", "Некоторые профессионалы не врачи", "Все профессионалы — врачи"], "Все врачи — профессионалы, доктор Адамс — врач, значит доктор Адамс — профессионал. Это прямое применение общеутвердительного силлогизма."],
    "TLR1_02": ["Все львы — животные. Симба — лев. Какой вывод вы можете сделать?", "Если каждый X относится к Y, а Симба — X…", ["Симба — животное", "Все животные — львы", "Симба не животное", "Некоторые животные не львы"], "Все львы — животные, Симба — лев, значит Симба — животное."],
    "TLR1_03": ["Все апельсины — фрукты. Этот предмет — апельсин. Какой вывод вы можете сделать?", "Если каждый апельсин — фрукт, а этот предмет — апельсин…", ["Этот предмет — фрукт", "Все фрукты — апельсины", "Этот предмет — овощ", "Этот предмет может быть не фруктом"], "Все апельсины — фрукты, этот предмет — апельсин, значит он — фрукт."],
    "TLR1_04": ["Все машины — транспортные средства. БМВ — машина. Какой вывод вы можете сделать?", "Машины — подмножество транспортных средств. Куда попадает БМВ?", ["БМВ — транспортное средство", "Все транспортные средства — машины", "БМВ — не транспортное средство", "Некоторые транспортные средства — не машины"], "Все машины — транспортные средства, БМВ — машина, значит БМВ — транспортное средство."],
    "TLR1_05": ["Ни одна птица не является насекомым. Малиновка — птица. Какой вывод вы можете сделать?", "Если ни один X не является Y, а малиновка — X…", ["Малиновка — не насекомое", "Малиновка — насекомое", "Некоторые насекомые — птицы", "Все малиновки — насекомые"], "Птицы не бывают насекомыми, малиновка — птица, значит малиновка не насекомое."],
    "TLR1_06": ["Весь лед холодный. Куб на столе сделан изо льда. Какой вывод вы можете сделать?", "Если все, что лед, холодно, а куб — ​​лед…", ["Куб холодный", "Куб теплый", "Не весь лед холодный", "Стол холодный"], "Весь лед холодный, а куб — ​​лед, поэтому куб холодный."],
    "TLR1_07": ["Все скрипки — музыкальные инструменты. Страдивари — скрипка. Какой вывод вы можете сделать?", "Скрипки входят в множество инструментов. Страдивари — это…", ["Страдивари — инструмент", "Все инструменты — скрипки", "Страдивари — не инструмент", "Некоторыми инструментами нельзя играть"], "Все скрипки — инструменты, Страдивари — скрипка, значит Страдивари — инструмент."],
    "TLR1_08": ["Все розы — растения. Этот экземпляр — роза. Какой вывод вы можете сделать?", "Розы — подмножество растений. Этот экземпляр — роза, значит…", ["Этот экземпляр — растение", "Все растения — розы", "Этот экземпляр — не растение", "Розы — не растения"], "Все розы — растения, этот экземпляр — роза, значит он — растение."],
    "TLR1_09": ["Любое золото металлическое. Это кольцо сделано из золота. Какой вывод вы можете сделать?", "Золото всегда металлическое. Кольцо золотое, так что…", ["Это кольцо металлическое", "Все металлические вещи — золото", "Это кольцо не металлическое.", "Золото иногда бывает неметаллическим"], "Любое золото металлическое. Кольцо золотое, поэтому кольцо металлическое."],
    "TLR1_10": ["Все реки содержат проточную воду. Амазонка — река. Какой вывод вы можете сделать?", "Если в каждой реке есть текущая вода, а Амазонка — это река…", ["Амазонка содержит проточную воду", "Вся текущая вода – это река", "Амазонка не содержит воды", "Некоторые реки пересыхают"], "Все реки содержат проточную воду. Амазонка — это река, поэтому в ней есть проточная вода."],
    "TLR1_11": ["Все романы — книги. Все книги содержат страницы. Какой вывод вы можете сделать?", "Свяжите цепочку: романы → книги → страницы.", ["Все романы содержат страницы", "Все страницы только в романах", "Некоторые книги — не романы", "Романы не содержат страниц"], "Все романы — книги, все книги содержат страницы, по транзитивности все романы содержат страницы."],
    "TLR1_12": ["Все повара умеют готовить. Пьер — повар. Какой вывод вы можете сделать?", "Если каждый повар умеет готовить, а Пьер — повар…", ["Пьер умеет готовить", "Каждый, кто умеет готовить, — повар", "Пьер не умеет готовить", "Некоторые повара не умеют готовить"], "Все повара умеют готовить, Пьер — повар, значит Пьер умеет готовить."],
    "TLR1_13": ["Все орлы — птицы. У всех птиц есть перья. Какой вывод вы можете сделать?", "Соедините множества: орлы ⊂ птицы ⊂ пернатые.", ["У всех орлов есть перья", "Все пернатые — орлы", "У орлов нет перьев", "Некоторые птицы — не орлы"], "Все орлы — птицы, у всех птиц есть перья, значит у всех орлов есть перья."],
    "TLR1_14": ["Все планеты вращаются вокруг звезды. Сатурн — планета. Какой вывод вы можете сделать?", "Планеты вращаются вокруг звезд. Сатурн — планета, поэтому…", ["Сатурн вращается вокруг звезды", "У всего, что вращается вокруг звезды, есть планеты", "Сатурн не вращается вокруг звезды", "Звезда вращается вокруг Сатурна"], "Все планеты вращаются вокруг звезды. Сатурн — планета, следовательно, Сатурн вращается вокруг звезды."],
    "TLR1_15": ["Все киты — млекопитающие. Синий кит — кит. Какой вывод вы можете сделать?", "Киты — подмножество млекопитающих. Синий кит — кит, значит…", ["Синий кит — млекопитающее", "Все млекопитающие — киты", "Синий кит — рыба", "Некоторые киты — не млекопитающие"], "Все киты — млекопитающие, синий кит — кит, значит синий кит — млекопитающее."],
    "TLR1_16": ["Ни одно травоядное не ест мяса. Кролик — травоядное. Какой вывод вы можете сделать?", "Если ни одно травоядное не ест мяса, а кролик — травоядное…", ["Кролик не ест мяса", "Кролик ест мясо", "Некоторые травоядные едят мясо", "Все хищники — кролики"], "Травоядные не едят мяса, кролик — травоядное, значит кролик не ест мяса."],
    "TLR1_17": ["Все щенки — собаки. Все собаки — псовые. Какой вывод вы можете сделать?", "Цепочка: щенки ⊂ собаки ⊂ псовые.", ["Все щенки — псовые", "Все псовые — щенки", "Щенки — не псовые", "Некоторые собаки — не псовые"], "Все щенки — собаки, все собаки — псовые, по транзитивности все щенки — псовые."],
    "TLR1_18": ["Все учителя работают в сфере образования. Мистер Браун — учитель. Какой вывод вы можете сделать?", "Если каждый учитель работает в сфере образования, а мистер Браун - учитель...", ["Г-н Браун работает в сфере образования", "Каждый в сфере образования является учителем", "Г-н Браун не работает в сфере образования", "Некоторые учителя не работают в сфере образования"], "Все учителя работают в сфере образования. Г-н Браун — учитель, поэтому он работает в сфере образования."],
    "TLR1_19": ["Все бриллианты — драгоценные камни. Все драгоценные камни ценны. Какой вывод вы можете сделать?", "Цепочка: бриллианты ⊂ драгоценные камни ⊂ ценные вещи.", ["Все бриллианты ценны", "Все ценные вещи — бриллианты", "Бриллианты не ценны", "Некоторые драгоценные камни бесценны"], "Все бриллианты — драгоценные камни, все драгоценные камни ценны, значит все бриллианты ценны."],
    "TLR1_20": ["Все летние дни теплые. Сегодня летний день. Какой вывод вы можете сделать?", "Если каждый летний день теплый, а сегодня летний день...", ["Сегодня тепло", "Все теплые дни - летние дни", "Сегодня холодно", "Летние дни не всегда теплые"], "Все летние дни теплые. Сегодня летний день, поэтому сегодня тепло."],
    "TLR2_01": ["Если идет снег, температура ниже нуля. Идет снег. Какой вывод вы можете сделать?", "Модус поненс: Если P→Q и P истинно, то Q должно быть истинным.", ["Температура ниже нуля", "Температура выше нуля", "Это не снег", "Никакого вывода сделать нельзя"], "Модус поненс: P→Q (снег → ниже нуля). P верно (снег), поэтому Q истинно (ниже нуля)."],
    "TLR2_02": ["Если вы занимаетесь регулярно, ваши оценки улучшаются. Ваши оценки не улучшились. Какой вывод вы можете сделать?", "Модус толленс: Если P→Q и Q ложно, то P должно быть ложным.", ["Вы не учились регулярно", "Вы регулярно учились", "Ваши оценки улучшились", "Учеба не влияет на оценки"], "Модус толленс: P→Q (учеба → улучшение оценок). Q — ложь (оценки не улучшились), поэтому P — ложь (не учился регулярно)."],
    "TLR2_03": ["Если телефон полностью заряжен, его хватает на целый день. Ваш телефон полностью заряжен. Какой вывод вы можете сделать?", "Предыстория верна. Примените модус поненс.", ["Ваш телефон прослужит целый день", "Ваш телефон не прослужит целый день", "Ваш телефон не заряжен", "Никакого вывода сделать нельзя"], "Модус поненс: P→Q (заряжен → действует весь день). P верно (полностью заряжен), поэтому Q верно (работает весь день)."],
    "TLR2_04": ["Если будильник установлен, он звонит в 7 утра. Будильник не прозвенел в 7 утра. Какой вывод вы можете сделать?", "Следствие ложное. Примените модус толленс.", ["Будильник не был установлен", "Будильник был установлен", "Будильник звонит в 7 утра.", "Сигнализация сломана"], "Режим звонка: P→Q (установка будильника → звонок в 7). Q ложно (не звонил), поэтому P ложно (не установлено)."],
    "TLR2_05": ["Если у вас есть правильный ключ, замок откроется. У вас есть правильный ключ. Какой вывод вы можете сделать?", "Предыстория верна. Примените модус поненс.", ["Замок открывается", "Замок не открывается", "У вас нет правильного ключа", "Замок заклинил"], "Модус поненс: P→Q (правильный ключ → замок открывается). P истинно (есть ключ), поэтому Q истинно (замок открывается)."],
    "TLR2_06": ["Если электричество есть, холодильник работает. Холодильник не работает. Какой вывод вы можете сделать?", "Следствие ложное. Примените модус толленс.", ["Электричество не включено", "Электричество включено", "Холодильник работает", "Никакого вывода сделать нельзя"], "Модус толленс: P→Q (электричество → работает холодильник). Q ложно (не работает), поэтому P ложно (отключено электричество)."],
    "TLR2_07": ["Если вы поливаете растения ежедневно, они останутся зелеными. Вы ежедневно поливаете растения. Какой вывод вы можете сделать?", "Условие (антецедент) выполнено. Что следует?", ["Ваши растения остаются зелеными", "Ваши растения завянут", "Вы их не поливаете", "Полив не даёт эффекта"], "Модус поненс: из P следует Q; P верно (вы поливаете), значит Q верно — растения зелёные."],
    "TLR2_08": ["Если в автомобиле есть топливо, двигатель можно запустить. Двигатель не может запуститься. Какой вывод вы можете сделать?", "Результата (последнего) не произошло. Примените модус толленс.", ["В машине нет топлива", "В машине есть топливо", "Двигатель запустился", "Никакого вывода сделать нельзя"], "Модус толленс: P→Q (топливо → запуск двигателя). Q ложно (двигатель не запускается), поэтому P ложно (нет топлива)."],
    "TLR2_09": ["Купив билет, вы сможете сесть на поезд. Вы купили билет. Какой вывод вы можете сделать?", "Вы выполнили условие. Что должно последовать?", ["Вы можете сесть на поезд", "Вы не можете сесть в поезд", "Вы не купили билет", "Поезд отменен"], "Модус поненс: P→Q (билет → посадка на поезд). P верно (билет куплен), поэтому Q истинно (можно сесть)."],
    "TLR2_10": ["Если у вас есть действующий паспорт, вы можете пересечь границу. Вы не можете пересечь границу. Какой вывод вы можете сделать?", "Вы не смогли бы выполнить Q. Если P→Q, что ¬Q скажет вам о P?", ["У вас нет действующего паспорта", "У вас есть действующий паспорт", "Вы пересекли границу", "Паспорта не требуются"], "Модус толленс: P→Q (паспорт → пересечение границы). Q ложно (невозможно пересечь границу), поэтому P ложно (нет действительного паспорта)."],
    "TLR2_11": ["Если животное — лошадь, то у нее четыре ноги. У этого животного четыре ноги. Какой вывод вы можете сделать?", "Знание истинности консеквента НЕ доказывает антецедент. У многих животных четыре ноги.", ["Мы не можем сделать вывод, что это лошадь", "Это точно лошадь", "У него две ноги", "Это не животное"], "Утверждение последствий является заблуждением. P→Q (лошадь → четыре ноги) и Q верно, НЕ означает, что P истинно. У многих животных, не являющихся лошадьми, четыре ноги."],
    "TLR2_12": ["Если человек — юрист, он изучал право. Сэм изучал право. Какой вывод вы можете сделать?", "Из одного лишь того, что следствие (Q) верно, нельзя заключать, что верно условие (P).", ["Нельзя заключить, что Сэм — юрист", "Сэм точно юрист", "Сэм не изучал право", "Все, кто изучал право, — юристы"], "Ошибка «утверждение следствия»: из P→Q (юрист → изучал право) и истинности Q (изучал право) не следует P (юрист). Многие изучают право и не становятся юристами."],
    "TLR2_13": ["Если духовка включена, на кухне становится тепло. Кухня не теплая. Какой вывод вы можете сделать?", "Следствие ложное — примените модус толленс.", ["Духовка не включена", "Духовка включена", "Кухня теплая", "Никакого вывода сделать нельзя"], "Модус толленс: P→Q (духовка включена → кухня теплая). Q ложно (не тепло), поэтому P ложно (духовка не включена)."],
    "TLR2_14": ["Если нажать на тормоз, машина замедляется. Вы нажали на тормоз. Какой вывод вы можете сделать?", "Условие выполнено — примените модус поненс.", ["Автомобиль замедляется", "Автомобиль ускоряется", "Вы не нажали тормоз", "Ничего не происходит"], "Модус поненс: P→Q (нажали тормоз → машина замедляется). P верно, значит Q верно — машина замедляется."],
    "TLR2_15": ["Если идет снег, небо облачное. Небо пасмурное. Какой вывод вы можете сделать?", "Облачное небо бывает и без снега.", ["Мы не можем сделать вывод, что идет снег", "Определенно идет снег", "Небо ясное", "В пасмурную погоду никогда не идет снег"], "Ошибка «утверждение следствия»: из «снег → облачно» и того, что небо облачно, не следует, что идёт снег."],
    "TLR2_16": ["Если аккумулятор заряжен, фонарик работает. Фонарик не работает. Какой вывод вы можете сделать?", "Следствие неверно — примените модус толленс к P→Q.", ["Аккумулятор не заряжен", "Аккумулятор заряжен", "Фонарик работает", "Никакого вывода сделать нельзя"], "Модус толленс: P→Q (заряжен → работает). Q ложно (не работает), значит P ложно — аккумулятор не заряжен."],
    "TLR2_17": ["Если добавить в чай сахар, чай станет сладким. Вы добавили сахар в чай. Какой вывод вы можете сделать?", "Условие выполнено — примените модус поненс.", ["Чай становится сладким", "Чай остаётся несладким", "Вы не добавили сахар", "Сахар не влияет"], "Модус поненс: добавили сахар → чай сладкий; условие выполнено, значит чай сладкий."],
    "TLR2_18": ["Если маршрутизатор Wi-Fi включен, устройства могут подключаться к Интернету. Устройства не могут подключиться к Интернету. Какой вывод вы можете сделать?", "Следствие ложно — примените модус толленс.", ["Маршрутизатор Wi-Fi не включен", "Маршрутизатор Wi-Fi включен", "Устройства могут подключаться", "Интернет не существует"], "Модус толленс: если роутер включён → есть доступ; доступа нет → роутер не включён."],
    "TLR2_19": ["Если студент записывается на курс, он получает учебную программу. Эмма записалась на курс. Какой вывод вы можете сделать?", "Эмма удовлетворила предшествующее. Что должно последовать?", ["Эмма получает учебную программу", "Эмма не получает учебную программу", "Эмма не записалась", "Курс не имеет учебной программы"], "Модус поненс: P→Q (зарегистрироваться → получить учебную программу). P верно (Эмма зачислена), поэтому Q верно (Эмма получает учебную программу)."],
    "TLR2_20": ["Если сегодня воскресенье, магазин закрыт. Сегодня не воскресенье. Какой вывод вы можете сделать?", "Из ложности условия не следует ни истинность, ни ложность следствия — это «отрицание антецедента».", ["Мы не можем сделать вывод, открыт ли магазин или закрыт", "Магазин точно открыт", "Магазин точно закрыт", "Сегодня суббота"], "Из P→Q и «не P» не следует ни Q, ни «не Q». Магазин может быть закрыт по другой причине."],
    "TLR3_01": ["Анна выше Даны. Дана выше Бена. Бен выше Карла. Кто самый низкий?", "Запишите цепочку неравенств и найдите «низ».", ["Карл", "Бен", "Дана", "Анна"], "Анна > Дана > Бен > Карл. Карл внизу — значит, самый низкий."],
    "TLR3_02": ["Феликс легче Джорджа. Гарри тяжелее Джорджа. Иван легче Феликса. Кто самый тяжёлый?", "Упорядочьте: Гарри > Джордж > Феликс > Иван.", ["Гарри", "Джордж", "Феликс", "Иван"], "Гарри > Джордж > Феликс > Иван. Самый тяжёлый — Гарри."],
    "TLR3_03": ["Мия младше Нины. Оскар старше Нины. Пэм младше Мии. Кто самый старший?", "Запишите: Оскар > Нина > Мия > Пэм. Кто наверху?", ["Оскар", "Нина", "Мия", "Пэм"], "Оскар > Нина > Мия > Пэм. Самый старший — Оскар."],
    "TLR3_04": ["В гонке Радж финишировал после Сэма. Тина финишировала раньше Сэма. Ума финишировала после Раджа. Кто пришёл первым?", "Раньше на финише = выше место. Цепочка: Тина — Сэм — Радж — Ума.", ["Тина", "Сэм", "Радж", "Ума"], "Порядок: Тина → Сэм → Радж → Ума. Первой — Тина."],
    "TLR3_05": ["Виктор зарабатывает меньше Венди. Венди зарабатывает меньше Ксавьера. Яра зарабатывает больше Ксавьера. Кто зарабатывает больше всех?", "Цепочка: Виктор < Венди < Ксавьер < Яра.", ["Яра", "Ксавьер", "Венди", "Виктор"], "Яра > Ксавьер > Венди > Виктор. Больше всех — Яра."],
    "TLR3_06": ["Ева набрала больше очков, чем Фрэнк. Грейс набрала меньше, чем Фрэнк. Дэйв набрал больше, чем Ева. У кого самый низкий балл?", "Цепочка: Дэйв > Ева > Фрэнк > Грейс. Кто внизу?", ["Грейс", "Фрэнк", "Ева", "Дэйв"], "Дэйв > Ева > Фрэнк > Грейс. Самый низкий балл у Грейс."],
    "TLR3_07": ["Лили плывёт быстрее Макса. Оливия плывёт быстрее Лили. Ной плывёт медленнее Макса. Кто самый медленный?", "По скорости: Оливия > Лили > Макс > Ной.", ["Ной", "Макс", "Лили", "Оливия"], "Оливия > Лили > Макс > Ной. Самый медленный — Ной."],
    "TLR3_08": ["Квинн ниже Рут. Стив выше Тома. Том выше Рут. Кто самый высокий?", "Цепочка: Стив > Том > Рут > Квинн.", ["Стив", "Том", "Рут", "Квинн"], "Стив > Том > Рут > Квинн. Самый высокий — Стив."],
    "TLR3_09": ["Эми весит меньше Брайана. Клара весит больше Дэна. Дэн весит больше Брайана. Кто самый лёгкий?", "Цепочка: Клара > Дэн > Брайан > Эми.", ["Эми", "Брайан", "Дэн", "Клара"], "Клара > Дэн > Брайан > Эми. Самая лёгкая — Эми."],
    "TLR3_10": ["Джейк бегает медленнее Ким. Лео бегает быстрее Моны. Мона бегает быстрее Ким. Кто второй по скорости?", "Цепочка: Лео > Мона > Ким > Джейк. Кто второй?", ["Мона", "Ким", "Лео", "Джейк"], "Лео > Мона > Ким > Джейк. Второй по скорости — Мона."],
    "TLR3_11": ["В группе из 20 студентов 12 играют в теннис и 10 в футбол. Каждый студент занимается хотя бы одним из этих видов спорта. Сколько играют в обе игры?", "Использование: Оба = A + B − Всего (когда каждый делает хотя бы одно).", ["2", "4", "8", "10"], "Оба = 12 + 10 − 20 = 2. Два ученика занимаются обоими видами спорта."],
    "TLR3_12": ["В группе из 25 человек 18 любят кофе и 13 — чай. Каждому нравится хотя бы один. Сколько любят и кофе, и чай?", "Оба вида = кофе + чай − всего.", ["6", "5", "7", "8"], "18 + 13 − 25 = 6 человек любят оба."],
    "TLR3_13": ["В компании из 35 сотрудников 20 говорят по-французски и 22 — по-немецки. Каждый сотрудник говорит хотя бы на одном из этих языков. Сколько человек говорят на обоих?", "Оба = французский + немецкий − итого.", ["7", "5", "8", "13"], "Оба = 20 + 22 − 35 = 7. Семь сотрудников говорят на обоих."],
    "TLR3_14": ["Из группы из 40 туристов 28 посетили музей, а 18 - парк. Каждый турист посетил хотя бы одно место. Сколько человек посетило оба?", "Оба = музей + парк − всего.", ["6", "10", "8", "4"], "Оба = 28 + 18 − 40 = 6. Оба посетили шесть туристов."],
    "TLR3_15": ["В группе из 30 читателей 16 читали художественную литературу и 20 — научно-популярную. Каждый читал хотя бы один тип. Сколько читали оба типа?", "Оба = художественная + научпоп − всего.", ["6", "4", "10", "14"], "16 + 20 − 30 = 6 читателей читали оба типа."],
    "TLR3_16": ["В ряду людей Алиса третья слева и пятая справа. Сколько человек в очереди?", "Итого = левая позиция + правая позиция — 1.", ["7", "8", "6", "9"], "Итого = 3 + 5 − 1 = 7. В ряду 7 человек."],
    "TLR3_17": ["По счету Боб 7-й слева и 4-й справа. Сколько человек в очереди?", "Итого = левая позиция + правая позиция — 1.", ["10", "11", "9", "12"], "Итого = 7 + 4 − 1 = 10. В ряду 10 человек."],
    "TLR3_18": ["В очереди Кэрол 5-я спереди и 9-я сзади. Сколько человек в очереди?", "Итого = передняя позиция + задняя позиция − 1.", ["13", "14", "12", "15"], "Итого = 5 + 9 − 1 = 13. В очереди 13 человек."],
    "TLR3_19": ["В шеренге Дэвид занимает 9-е место спереди и 3-е место сзади. Сколько человек в очереди?", "Итого = передняя позиция + задняя позиция − 1.", ["11", "12", "10", "13"], "Итого = 9 + 3 − 1 = 11. В очереди 11 человек."],
    "TLR3_20": ["Эмили подряд 6-я слева и 6-я справа. Сколько человек в очереди?", "Итого = левая позиция + правая позиция — 1.", ["11", "12", "10", "13"], "Итого = 6 + 6 − 1 = 11. В ряду 11 человек."],
    "TLR4_01": ["Пятерых сравнивают по весу. E тяжелее A, A тяжелее B, C тяжелее D, D тяжелее B, A тяжелее C. Расположите от самого тяжёлого к самому лёгкому.", "Соберите цепочку: E > A > C > D > B.", ["E, A, C, D, B", "E, A, D, C, B", "A, E, C, D, B", "E, C, A, D, B"], "E > A > C > D > B. Самый тяжёлый — E, самый лёгкий — B."],
    "TLR4_02": ["Пять бегунов финишируют. Сэм приходит раньше Прии, Прия раньше Куинн, Куинн раньше Тары, Тара раньше Розы. Кто третий?", "Цепочка финиша: Сэм → Прия → Куинн → Тара → Роза.", ["Куинн", "Прия", "Тара", "Сэм"], "Порядок: Сэм, Прия, Куинн, Тара, Роза. Третий — Куинн."],
    "TLR4_03": ["У пяти студентов разные баллы за тест. У Джека больше, чем у Фреда; у Фреда больше, чем у Джины; у Джины больше, чем у Айрис; у Айрис больше, чем у Хэнка. У кого второй с конца результат (предпоследнее место)?", "Цепочка: Джек > Фред > Джина > Айрис > Хэнк. Считайте снизу вверх.", ["Айрис", "Джина", "Хэнк", "Фред"], "Джек > Фред > Джина > Айрис > Хэнк. Снизу: Хэнк, Айрис… Второй снизу — Айрис."],
    "TLR4_04": ["Шестеро спортсменов по скорости: Диана быстрее Авы, Ава быстрее Беллы, Белла быстрее Хлои, Елена быстрее Дианы, Фиона медленнее Хлои. Расположите от самого быстрого к самому медленному.", "Соберите: Елена > Диана > Ава > Белла > Хлоя > Фиона.", ["Елена, Диана, Ава, Белла, Хлоя, Фиона", "Диана, Елена, Ава, Белла, Хлоя, Фиона", "Елена, Ава, Диана, Белла, Хлоя, Фиона", "Елена, Диана, Белла, Ава, Хлоя, Фиона"], "Елена > Диана > Ава > Белла > Хлоя > Фиона."],
    "TLR4_05": ["Пять городов по числу жителей: в Пенни больше, чем в Лиаме; в Лиаме больше, чем в Мейсоне; в Ное меньше, чем в Оливере; в Оливере меньше, чем в Мейсоне. Упорядочьте от самого населённого к самому маленькому.", "Цепочка: Пенни > Лиам > Мейсон > Оливер > Ной.", ["Пенни, Лиам, Мейсон, Оливер, Ной", "Лиам, Пенни, Мейсон, Оливер, Ной", "Пенни, Мейсон, Лиам, Оливер, Ной", "Пенни, Лиам, Оливер, Мейсон, Ной"], "Пенни > Лиам > Мейсон > Оливер > Ной."],
    "TLR4_06": ["В компании из 60 сотрудников 38 используют Windows и 30 — Mac. Каждый сотрудник использует хотя бы одну операционную систему. Сколько человек использует оба?", "Оба = Windows + Mac — Итого.", ["8", "10", "12", "6"], "Оба = 38 + 30 − 60 = 8."],
    "TLR4_07": ["В школе из 80 учеников 55 изучают математику и 42 — естествознание. Каждый студент изучает как минимум один предмет. Сколько изучают оба?", "Оба = Математика + Наука − Итого.", ["17", "15", "20", "23"], "Оба = 55 + 42 − 80 = 17."],
    "TLR4_08": ["В клубе 75 человек: 50 играют в шахматы и 40 — в шашки. Каждый участник играет как минимум в одну игру. Сколько играют в обе игры?", "Оба = шахматы + шашки − сумма.", ["15", "10", "20", "25"], "Оба = 50 + 40 − 75 = 15."],
    "TLR4_09": ["По данным опроса 90 человек, 60 любят шоколад и 52 — ваниль. Каждому нравится хотя бы один вкус. Сколько любят оба вкуса?", "Оба = шоколад + ваниль − всего.", ["22", "18", "30", "12"], "60 + 52 − 90 = 22."],
    "TLR4_10": ["В группе из 100 избирателей 72 поддерживают предложение А и 65 поддерживают предложение Б. Каждый избиратель поддерживает хотя бы одно предложение. Сколько поддерживают оба?", "Оба = A + B − Итого.", ["37", "35", "40", "28"], "Оба = 72 + 65 − 100 = 37."],
    "TLR4_11": ["В опросе 50 человек 30 владеют автомобилем, 25 — велосипедом, а 10 — и тем, и другим. Кто из них не владеет ни тем, ни другим?", "По крайней мере один = автомобиль + велосипед − оба. Ни один = всего − хотя бы один.", ["5", "10", "15", "0"], "Хотя бы один = 30 + 25 − 10 = 45. Ни один = 50 − 45 = 5."],
    "TLR4_12": ["В классе из 45 учеников 28 сдали математику, 20 — естественные науки, а 8 — и то, и другое. Сколько сдали ровно один предмет?", "Ровно один = (только математика) + (только наука) = (28−8) + (20−8).", ["32", "40", "28", "20"], "Только математика = 28 − 8 = 20. Только естествознание = 20 − 8 = 12. Ровно один = 20 + 12 = 32."],
    "TLR4_13": ["В группе из 60 человек 40 играют на гитаре, 30 — на фортепиано, и каждый играет хотя бы на одном инструменте. Сколько человек играют ровно на одном инструменте?", "Сначала найдите Оба = гитара + фортепиано − всего. Тогда ровно один = всего − оба.", ["50", "60", "40", "30"], "Оба = 40 + 30 − 60 = 10. Ровно один = 60 − 10 = 50 (или, что то же самое, (40−10) + (30−10) = 30 + 20 = 50)."],
    "TLR4_14": ["В школе из 55 учеников 32 вступили в художественный кружок, 28 - в музыкальный кружок, а 12 - в оба. Сколько человек не присоединились ни к одному из клубов?", "Хотя бы один = искусство + музыка − и то, и другое. Ни один = всего − хотя бы один.", ["7", "5", "10", "3"], "Хотя бы один = 32 + 28 − 12 = 48. Ни один = 55 − 48 = 7."],
    "TLR4_15": ["При опросе 70 человек 45 читают газеты, 38 читают журналы, а 20 читают и то, и другое. Сколько человек читают ровно один тип публикаций?", "Ровно один = (только газета) + (только журнал).", ["43", "63", "50", "33"], "Только газета = 45 − 20 = 25. Только журнал = 38 − 20 = 18. Ровно один = 25 + 18 = 43."],
    "TLR4_16": ["Если холодно, Том носит куртку. Если Том носит куртку, он приносит с собой зонтик. Холодно. Что приносит Том?", "Соедините импликации: холод → куртка → зонт. Дважды модус поненс.", ["Зонтик", "Шляпа", "Ничего", "Только куртка"], "Холод → куртка → зонтик. Холодно, значит с зонтиком."],
    "TLR4_17": ["Если Алиса учится, она сдаёт экзамен. Если сдаст экзамен, получит диплом. Если получит диплом, ей предложат работу. Алиса учится. Каков итог?", "Цепочка условий: учёба → экзамен → диплом → работа. Применяйте модус поненс по шагам.", ["Алиса получит предложение о работе", "Алиса только сдаёт экзамен", "Алиса только получает диплом", "Никакого вывода сделать нельзя"], "По цепочке из трёх импликаций и факта «Алиса учится» следует, что ей предложат работу."],
    "TLR4_18": ["Если отключится электричество, компьютер выключится. Если компьютер выключается, несохранённая работа теряется. Работа не пропала. Какой вывод вы можете сделать?", "Цепочка модуса толленс с конца: работа цела → компьютер не выключился → свет не отключался.", ["Электричество не отключалось", "Электричество отключилось", "Компьютер выключился", "Работа была потеряна"], "Работа не потеряна → компьютер не выключался → питание не отключалось."],
    "TLR4_19": ["Если идет дождь, матч отменяется. В случае отмены матча билеты возвращаются. Билеты не были возвращены. Какой вывод вы можете сделать?", "Цепочка модуса толленса: не возвращены → не отменён → не было дождя.", ["Дождя не было", "Шёл дождь", "Матч был отменён", "Билеты были возвращены"], "Билеты не вернулись → матч не отменён → дождя не было."],
    "TLR4_20": ["Если вы едите слишком много сахара, вы набираете вес. Если вы набираете вес, вам нужно больше заниматься спортом. Если нужно больше упражнений, вы ходите в спортзал. Вы не ходили в спортзал. Какой вывод?", "Трижды модус толленс: не зал → не нужен спорт → нет лишнего веса → не переедали сахар.", ["Вы не ели слишком много сахара", "Вы ели слишком много сахара", "Вы набрали вес", "Вы записались в спортзал"], "Не были в зале → цепочка импликаций в обратную сторону → вы не переедали сахар."],
    "TLR5_01": ["Три человека: А, Б и С. Ровно один говорит правду. А говорит: «Б и С — оба лжецы». Б говорит: «А — лжец». С говорит: «А говорит правду». Кто говорит правду?", "Проверьте по очереди каждого как единственного правдивого — должно сойтись без противоречий.", ["Б", "А", "С", "Ни один"], "Если правду говорит Б: А лжёт, значит не оба Б и С лжецы; С лжёт, говоря что А правдив — согласуется. Другие варианты противоречат условию."],
    "TLR5_02": ["Трое: D, E и F. Ровно один говорит правду. D говорит: «E — лжец». E говорит: «F — лжец». F говорит: «D и E оба лжецы». Кто говорит правду?", "Предположите по очереди, что правду говорит каждый, и ищите противоречия.", ["E", "D", "F", "Ни один"], "Если правду говорит E: F лжёт ✓. D говорит «E — лжец» — ложь, значит E не лжец ✓. F лжёт, значит неверно, что D и E оба лжцы — хотя бы один говорит правду, это E ✓. Только E согласовано с условием."],
    "TLR5_03": ["G, H и I — подозреваемые. Виновен ровно один. Виновный всегда лжёт, невиновные всегда говорят правду. G говорит: «Виновен H». H говорит: «Я не виновен». I говорит: «Виновен G». Кто виноват?", "Предположите по очереди виноватого (он лжёт) и проверьте высказывания остальных.", ["G", "H", "I", "Нельзя определить"], "Если виновен G: он лжёт → H не виновен ✓. H (невиновен) правдив: «Я не виновен» ✓. I (невиновен) правдив: «Виновен G» ✓. Остальные варианты дают противоречия."],
    "TLR5_04": ["J, K и L что-то заявляют. Ровно один говорит правду. J говорит: «Я говорю правду». K говорит: «J говорит правду». L говорит: «J — лжец». Кто говорит правду?", "Если бы правду говорил J, чему тогда соответствует фраза K? Проверьте каждого.", ["L", "J", "K", "Ни один"], "Если правду говорит L: J — лжец ✓. J лжёт, значит «я говорю правду» — ложь ✓. K лжёт, значит «J говорит правду» — ложь ✓. Только L согласовано; если правдивы J или K, получаются двое правдивых."],
    "TLR5_05": ["Каждый из M, N и O делает заявление. Ровно один говорит правду. M говорит: «N и O оба говорят правду». N говорит: «M — лжец». O говорит: «N — лжец». Кто говорит правду?", "Если M правдив, то и N, и O правдивы — тогда правдивых больше одного. Переберите остальные варианты.", ["N", "M", "O", "Ни один"], "Если правду говорит N: M лжёт; его фраза ложна — не оба N и O правдивы; O лжёт, что «N — лжец», значит N не лжец. Согласуется только с одним правдивым — N."],
    "TLR5_06": ["Если через три дня будет среда, какой день сегодня?", "Отсчитайте назад три дня, начиная со среды.", ["Воскресенье", "Понедельник", "Суббота", "Вторник"], "Сегодня + 3 = среда. Обратный отсчет: среда − 1 = вторник, − 2 = понедельник, − 3 = воскресенье. Сегодня воскресенье."],
    "TLR5_07": ["Если вчера была пятница, какой день будет послезавтра?", "Сначала найдите сегодняшний день, а затем отсчитайте два дня вперед.", ["Понедельник", "Воскресенье", "Вторник", "Суббота"], "Вчера = пятница → сегодня = суббота → завтра = воскресенье → послезавтра = понедельник."],
    "TLR5_08": ["Если два дня назад был понедельник, какой день будет через три дня?", "Найдите сегодняшний день по значению «два дня назад», а затем прибавьте три дня.", ["Суббота", "Пятница", "Воскресенье", "Четверг"], "Два дня назад = понедельник → сегодня = среда → через три дня = суббота."],
    "TLR5_09": ["Если позавчера был четверг, какой день завтра?", "Позавчера = два дня назад. Найдите сегодняшний день и добавьте его.", ["Воскресенье", "Суббота", "Понедельник", "Пятница"], "Позавчера = четверг → вчера = пятница → сегодня = суббота → завтра = воскресенье."],
    "TLR5_10": ["Если через четыре дня будет вторник, какой день был вчера?", "Найдите сегодняшний день, вычитая 4 из вторника, а затем вычитая еще 1 из вчерашнего дня.", ["Четверг", "Пятница", "Среда", "Суббота"], "Сегодня + 4 = вторник → сегодня = вторник − 4 = пятница. Вчера = Четверг."],
    "TLR5_11": ["Шесть студентов ранжируются по результатам тестов. Фэй набрала больше очков, чем Диана. Диана набрала больше баллов, чем Эбби. Эбби набрала больше очков, чем Брайан. Брайан набрал больше очков, чем Карл. Карл набрал больше, чем Елена. Кто набрал третье место?", "Постройте полную цепочку от высшего к низшему и досчитайте до позиции 3.", ["Эбби", "Диана", "Брайан", "Фэй"], "Фэй > Диана > Эбби > Брайан > Карл > Елена. Третье место — Эбби."],
    "TLR5_12": ["Пять банок разного веса. Банка 5 тяжелее банки 1. Банка 1 тяжелее банки 2. Банка 2 тяжелее банки 4. Банка 4 тяжелее банки 3. Какая банка на среднем месте (3-я из 5)?", "Цепочка: 5 > 1 > 2 > 4 > 3. Среднее — третья по порядку.", ["Банка 2", "Банка 1", "Банка 4", "Банка 3"], "Банка 5 > 1 > 2 > 4 > 3. На третьем месте — банка 2."],
    "TLR5_13": ["Семеро выстроены по возрасту: T старше U, U старше V, V старше W, W старше X, X старше Y, Y старше Z. Кто четвёртый по старшинству?", "Цепочка: T > U > V > W > X > Y > Z. Считайте до 4-го места.", ["W", "V", "X", "Y"], "T > U > V > W > X > Y > Z. Четвёртый (самый старший из оставшихся после тройки лидеров) — W."],
    "TLR5_14": ["Пять городов, ранжированных по численности населения: в городе E больше людей, чем в A; в A больше, чем в B; в B больше, чем в D; в D больше, чем в C. Какой город наименее населён?", "Постройте цепочку E > A > B > D > C.", ["Город C", "Город D", "Город B", "Город A"], "E > A > B > D > C. Наименее населён город C."],
    "TLR5_15": ["Шесть книг по числу страниц: в T больше, чем в P; в P больше, чем в Q; в Q больше, чем в U; в U больше, чем в R; в R больше, чем в S. Какая книга вторая по минимуму страниц (вторая с конца)?", "Цепочка: T > P > Q > U > R > S. «Вторая с конца» — предпоследняя в ряду.", ["Книга R", "Книга S", "Книга U", "Книга Q"], "T > P > Q > U > R > S. Меньше всего страниц у S, следующая — R. Ответ: книга R."],
    "TLR5_16": ["Три коробки подписаны «Яблоки», «Апельсины» и «Смешанная». Все надписи неверны. Из коробки с надписью «Смешанная» вы достаёте яблоко. Что на самом деле лежит в коробке с надписью «Яблоки»?", "Надпись «Смешанная» ложна — внутри не смесь. Раз достали яблоко, эта коробка целиком с яблоками. Распределите оставшиеся два содержимых.", ["Апельсины", "Яблоки", "Смешанные", "Нельзя определить"], "«Смешанная» не смесь; вытащили яблоко — значит там только яблоки. Остались по сути апельсины и смесь для двух других коробок. На «Апельсинах» не могут быть апельсины (этикетка ложна) — там смесь. На «Яблоках» не яблоки — там апельсины."],
    "TLR5_17": ["Алиса, Боб и Кэрол работают в разные дни: понедельник, вторник или среду. Алиса не работает по понедельникам. Боб не работает во вторник и среду. Кэрол не работает в среду. В какой день Кэрол работает?", "Начинается с самого сдержанного человека. Боб может работать только один день.", ["Вторник", "Понедельник", "Среда", "Невозможно определить"], "Боб не может работать во вторник или среду → Боб работает в понедельник. Алиса не может работать в понедельник → Алиса работает во вторник или среду. Кэрол не может работать в среду → Кэрол работает во вторник. Алиса работает в среду."],
    "TLR5_18": ["Если P истинно, то Q истинно. Если Q истинно, то R ложно. Если R ложно, то S истинно. P истинно. Истинно ли S?", "Идите по цепочке: P → Q → ложность R → S.", ["S истинно", "S ложно", "О S нельзя судить", "Зависит от P"], "P истинно → Q истинно → R ложно → по условию S истинно."],
    "TLR5_19": ["Пятеро друзей разного возраста. Алекс старше Дрю, Дрю старше Блейка, Блейк старше Кейси, Кейси старше Элли. Кто средний по возрасту (третий по старшинству)?", "Полная цепочка: Алекс > Дрю > Блейк > Кейси > Элли. Средний из пяти — на 3-й позиции.", ["Блейк", "Дрю", "Кейси", "Алекс"], "Алекс > Дрю > Блейк > Кейси > Элли. Третий по старшинству — Блейк."],
    "TLR5_20": ["В логическом турнире пять участников (V, W, X, Y, Z) занимают места с 1 по 5. V финиширует впереди W. X — сразу после Y. Z на 3-м месте. W на 5-м. Y впереди Z. На каком месте V?", "Зафиксируйте Z=3 и W=5; подберите порядок Y и X без конфликта.", ["4-й", "1-й", "2-й", "3-й"], "Z — 3-е, W — 5-е. Y впереди Z → Y на 1-м или 2-м; X сразу после Y. Если Y=2, то X=3, но там Z — нельзя. Значит Y=1, X=2, Z=3; остаются 4 и 5 для V и W; W пятый → V четвёртый."],
    "TSR1_01": ["Сколько сторон у пятиугольника?", "Префикс «пента-» относится к определенному числу.", ["5", "4", "6", "7"], "«Пентагон» происходит от греческого слова «пять». У пятиугольника ровно 5 сторон."],
    "TSR1_02": ["Сколько сторон у шестиугольника?", "Префикс «гекса-» означает число — представьте себе шестнадцатеричное.", ["6", "5", "8", "7"], "«Шестиугольник» происходит от греческого слова «шесть». У шестиугольника 6 сторон."],
    "TSR1_03": ["Сколько сторон у восьмиугольника?", "Подумайте об «осьминоге» — сколько у него рук?", ["8", "6", "10", "7"], "Приставка «окта-» означает восемь, точно так же, как у осьминога восемь рук. У восьмиугольника 8 сторон."],
    "TSR1_04": ["Сколько углов у треугольника?", "Префикс «три-» напрямую сообщает вам ответ.", ["3", "4", "2", "1"], "Треугольник имеет три угла — по одному в каждой вершине, где сходятся две стороны."],
    "TSR1_05": ["Сколько углов у пятиугольника?", "Каждая сторона встречается со следующей стороной под углом. Посчитайте стороны.", ["5", "4", "6", "3"], "Любой многоугольник имеет столько углов, сколько сторон. Пятиугольник имеет 5 сторон и 5 углов."],
    "TSR1_06": ["Сколько граней у прямоугольной коробки (прямоугольной призмы)?", "Подумайте о верхе, низу, переде, спине, левом и правом.", ["6", "4", "8", "5"], "У прямоугольной призмы шесть граней: верхняя, нижняя, передняя, ​​задняя, ​​левая и правая."],
    "TSR1_07": ["Сколько вершин (углов) имеет треугольник?", "Вершина – это место встречи двух сторон. Посчитайте углы.", ["3", "4", "2", "6"], "Треугольник имеет три вершины — по одной в каждом углу, где встречаются две стороны."],
    "TSR1_08": ["Какая двумерная фигура имеет ровно 3 стороны и 3 угла?", "Это один из самых простых многоугольников.", ["Треугольник", "Квадрат", "Пентагон", "Круг"], "Треугольник – это многоугольник, у которого 3 стороны и 3 угла."],
    "TSR1_09": ["Если сложить лист бумаги пополам один раз, сколько слоев бумаги у вас получится?", "Перед складыванием у вас есть 1 слой. Складывание удваивает счет.", ["2", "1", "3", "4"], "Каждый сгиб пополам удваивает количество слоев. Стоя с 1, одна складка дает 2 слоя."],
    "TSR1_10": ["Какую форму имеет каждая грань стандартного куба?", "Все грани куба одинаковы. Какая правильная фигура имеет 4 равные стороны и 4 прямых угла?", ["Квадрат", "Прямоугольник", "Треугольник", "Круг"], "У куба шесть граней, и каждая из них является квадратом."],
    "TSR1_11": ["Какая трехмерная фигура выглядит одинаково, независимо от того, как вы разрезаете ее центр?", "Эта форма не имеет ни рёбер, ни вершин, она идеально круглая.", ["Сфера", "Цилиндр", "Конус", "Куб"], "Сфера совершенно симметрична. Любой разрез через её центр даёт идентичный круг."],
    "TSR1_12": ["Сколько прямых сторон у круга?", "Везде круг изогнут. Есть ли прямые части?", ["0", "1", "2", "бесконечный"], "У круга вообще нет прямых сторон — это непрерывная кривая без углов и прямых сегментов."],
    "TSR1_13": ["Сколько сторон у треугольника?", "Название говорит вам: «три» означает три.", ["3", "2", "4", "5"], "Треугольник – это многоугольник, у которого ровно 3 стороны."],
    "TSR1_14": ["Сколько сторон у квадрата?", "Представьте себе оконное стекло или шахматную доску.", ["4", "3", "5", "6"], "У квадрата 4 равные стороны и 4 прямых угла."],
    "TSR1_15": ["Сколько вершин (углов) у квадрата?", "Подсчитайте точки, где встречаются две стороны.", ["4", "3", "5", "6"], "У квадрата 4 вершины — по одной в каждом углу."],
    "TSR1_16": ["Сколько вершин имеет шестиугольник?", "У многоугольника всегда одинаковое количество вершин и сторон.", ["6", "5", "8", "4"], "У шестиугольника 6 сторон и, следовательно, 6 вершин."],
    "TSR1_17": ["Если дважды сложить лист бумаги пополам, сколько слоев у вас получится?", "Каждый сгиб удваивает текущее количество слоев.", ["4", "2", "3", "8"], "Первый сгиб: 1 → 2 слоя. Второй сгиб: 2 → 4 слоя."],
    "TSR1_18": ["У какой фигуры четыре стороны, все углы которых равны 90°, а противоположные стороны параллельны?", "Это наиболее распространенная форма дверей, ширм и книг.", ["Прямоугольник", "Трапеция", "Ромб", "Параллелограмм"], "У прямоугольника 4 стороны, противоположные стороны параллельны, а все внутренние углы равны 90°."],
    "TSR1_19": ["Сколько углов у прямоугольника?", "Угол – это место, где две стороны встречаются под углом.", ["4", "2", "3", "5"], "Прямоугольник имеет четыре угла (вершины), по одному на каждом из четырех прямых углов."],
    "TSR1_20": ["У какой двумерной фигуры все точки на границе находятся на одинаковом расстоянии от центра?", "Представьте себе монету, вид сверху, или пиццу.", ["Круг", "Эллипс", "Квадрат", "Овал"], "Окружность определяется как совокупность всех точек, равноудалённых от центральной точки. Это постоянное расстояние и есть радиус."],
    "TSR2_01": ["Сколько ребер у прямоугольной призмы (коробки)?", "Посчитайте ребра на верхней грани, нижней грани и вертикальных ребрах, соединяющих их.", ["12", "8", "10", "6"], "Прямоугольная призма имеет 4 ребра сверху + 4 снизу + 4 вертикальных ребра = всего 12 ребер."],
    "TSR2_02": ["Сколько вершин имеет прямоугольная призма?", "Посчитайте углы на верхней и нижней грани отдельно.", ["8", "6", "10", "12"], "Прямоугольная призма имеет 4 вершины сверху и 4 снизу = всего 8 вершин."],
    "TSR2_03": ["Сколько граней у пятиугольной призмы?", "Призма с n-сторонним основанием имеет n прямоугольных боковых граней плюс 2 основания.", ["7", "5", "10", "6"], "Пятиугольная призма имеет 2 пятиугольных основания + 5 прямоугольных боковых граней = 7 граней."],
    "TSR2_04": ["Сколько ребер у треугольной призмы?", "Посчитайте ребра на каждом треугольном основании, затем ребра, соединяющие их.", ["9", "6", "8", "12"], "Треугольная призма имеет 3 ребра сверху + 3 снизу + 3 соединительных ребра = всего 9."],
    "TSR2_05": ["Сколько вершин имеет треугольная призма?", "Каждое треугольное основание имеет свой собственный набор вершин.", ["6", "5", "8", "9"], "Треугольная призма имеет по 3 вершины в каждом треугольном основании: 3 + 3 = 6 вершин."],
    "TSR2_06": ["Если 4 одинаковых кубика выстроить в одну линию, причем каждый из них имеет общую грань с соседним, сколько всего граней (включая нижнюю) будет видно?", "Сначала все грани четырёх кубов, затем вычтите скрытые пары на каждом стыке.", ["18", "20", "16", "24"], "У 4 кубиков 24 грани. 3 стыка × 2 скрытые грани = 6 скрытых. 24 − 6 = 18 видимых."],
    "TSR2_07": ["Сколько граней у шестиугольной призмы?", "Призма, основанная на n-стороннем многоугольнике, имеет n + 2 грани.", ["8", "6", "12", "10"], "Шестиугольная призма имеет 2 шестиугольных основания + 6 прямоугольных сторон = 8 граней."],
    "TSR2_08": ["Сколько ребер у пятиугольной призмы?", "У любой призмы с n-сторонним основанием общее количество ребер равно 3n.", ["15", "10", "12", "20"], "Пятиугольная призма: 5 ребер сверху + 5 снизу + 5 вертикальных = 3 × 5 = 15 ребер."],
    "TSR2_09": ["Сколько вершин имеет пятиугольная призма?", "Призма удваивает вершины своего базового многоугольника.", ["10", "12", "8", "15"], "Пятиугольная призма имеет по 5 вершин в каждом основании: 5×2 = 10 вершин."],
    "TSR2_10": ["Сколько ребер у квадратной пирамиды?", "Подсчитайте ребра основания, затем ребра от каждого угла основания до вершины.", ["8", "5", "6", "10"], "Пирамида с квадратным основанием имеет 4 ребра основания + 4 боковых ребра к вершине = 8 ребер."],
    "TSR2_11": ["Сколько вершин имеет квадратная пирамида?", "Не забудьте вершину наверху!", ["5", "4", "6", "8"], "4 угла основания + 1 вершина пирамиды = 5 вершин."],
    "TSR2_12": ["Сколько граней у квадратной пирамиды?", "Посчитайте основания и каждую треугольную боковую грань.", ["5", "4", "6", "8"], "Пирамида с квадратным основанием имеет 1 квадратное основание + 4 треугольные грани = 5 граней."],
    "TSR2_13": ["Сколько ребер у шестиугольной призмы?", "Примените формулу: ребер = 3 × (количество сторон в основании).", ["18", "12", "24", "15"], "Шестиугольная призма: 6 верхних ребер + 6 нижних ребер + 6 вертикальных ребер = 3 × 6 = 18 ребер."],
    "TSR2_14": ["Сколько вершин имеет шестиугольная призма?", "Каждое шестиугольное основание имеет 6 углов.", ["12", "8", "6", "18"], "Шестиугольная призма имеет 6 вершин в основании × 2 основания = 12 вершин."],
    "TSR2_15": ["Если 5 одинаковых кубиков расположить на одной прямой с общими гранями, сколько всего граней (включая нижнюю) будет видно?", "5×6 граней минус скрытые пары на стыках.", ["22", "20", "24", "26"], "30 граней − 4 стыка × 2 = 22 видимых."],
    "TSR2_16": ["Сколько граней у восьмиугольной призмы?", "Формула призмы: n + 2 грани для n-стороннего основания.", ["10", "8", "12", "16"], "Восьмиугольная призма имеет 2 восьмиугольных основания + 8 прямоугольных сторон = 10 граней."],
    "TSR2_17": ["Сколько ребер у восьмиугольной призмы?", "Формула призмы: 3n ребер для n-стороннего основания.", ["24", "16", "20", "32"], "Восьмиугольная призма имеет 3 × 8 = 24 ребра."],
    "TSR2_18": ["Сколько вершин имеет треугольная пирамида (тетраэдр)?", "Треугольная пирамида имеет треугольное основание и одну вершину.", ["4", "3", "5", "6"], "У тетраэдра 3 вершины основания + 1 вершина = 4 вершины."],
    "TSR2_19": ["Формула Эйлера гласит: V − E + F = 2 для выпуклых многогранников. Сколько у многогранника граней, если у него 6 вершин и 12 ребер?", "Переставим: F = 2 − V + E.", ["8", "6", "10", "7"], "F = 2 − V + E = 2 − 6 + 12 = 8 граней. (Это соответствует кубу или правильному октаэдру.)"],
    "TSR2_20": ["Сколько диагоналей у квадрата?", "Диагональ соединяет две несмежные вершины. У квадрата 4 вершины.", ["2", "4", "1", "3"], "У квадрата есть две диагонали, каждая из которых соединяет противоположные углы."],
    "TSR3_01": ["На всех гранях нарисован кубик 3х3х3, затем разрезан на 27 маленьких кубиков. Сколько маленьких кубиков имеют хотя бы одну закрашенную грань?", "Только куб в самом центре 3×3×3 не имеет краски. Сколько кубиков НЕТ в центре?", ["26", "24", "20", "27"], "Только у 1 куба (в центре) 0 закрашенных граней. Значит, у 27 − 1 = 26 кубиков есть хотя бы одна закрашенная грань."],
    "TSR3_02": ["Куб 3х3х3 разрисован на всех гранях и разрезан на 27 маленьких кубиков. Каково общее количество закрашенных граней во всех 27 маленьких кубиках?", "Каждая из 6 исходных граней представляет собой сетку 3×3 из 9 окрашенных граней.", ["54", "48", "36", "27"], "Каждая из 6 граней исходного куба составляет 9 окрашенных единичных граней: 6 × 9 = 54."],
    "TSR3_03": ["Раскрашенный кубик 3х3х3 разрезан на 27 маленьких кубиков. Сколько маленьких кубиков имеют не более 1 закрашенной грани?", "Посчитайте кубики с 0 нарисованными гранями и 1 нарисованной гранью, а затем сложите их.", ["7", "6", "8", "12"], "У 1 куба 0 закрашенных граней (центр), а у 6 кубиков ровно 1 (центр грани). Итого: 1+6=7."],
    "TSR3_04": ["Раскрашенный кубик 3х3х3 разрезан на 27 маленьких кубиков. Сколько маленьких кубиков имеют хотя бы две закрашенные грани?", "Это угловые кубики (3 стороны) и реберные кубики (2 стороны).", ["20", "12", "8", "18"], "8 углов (3 закрашенных) + 12 ребер (2 закрашенных) = 20 кубиков с 2 и более закрашенными гранями."],
    "TSR3_05": ["Если разрезать куб плоскостью, параллельной одной из его граней, какой формы будет поперечное сечение?", "Разрез, параллельный квадратной грани, дает форму, соответствующую этой грани.", ["Квадрат", "Прямоугольник", "Треугольник", "Шестиугольник"], "Плоскость, параллельная грани куба, равномерно пересекает четыре ребра, образуя квадрат."],
    "TSR3_06": ["Какую форму будет иметь поперечное сечение, если разрезать цилиндр плоскостью, перпендикулярной его оси?", "Ось проходит через центр двух круглых оснований.", ["Круг", "Эллипс", "Прямоугольник", "Овал"], "Разрез, перпендикулярный оси цилиндра, параллелен его круглым основаниям и образует круг."],
    "TSR3_07": ["Какую форму вы получите, если разрезать конус плоскостью, параллельной его круглому основанию?", "Основание конуса — круг; параллельный сечению сечение тоже круг.", ["Круг", "Эллипс", "Треугольник", "Парабола"], "Плоскость, параллельная основанию, даёт круг меньшего радиуса."],
    "TSR3_08": ["Сколько вершин имеет сфера?", "Вершина — это точка, где сходятся ребра. Есть ли у сферы края?", ["0", "1", "2", "бесконечный"], "Сфера — это идеально гладкая поверхность без краев и, следовательно, без вершин."],
    "TSR3_09": ["Сколько ребер у сферы?", "Ребро — это отрезок линии, где встречаются две плоские грани.", ["0", "1", "2", "бесконечный"], "У сферы нет плоских граней, поэтому у нее вообще нет краев."],
    "TSR3_10": ["Сколько граней у шестиугольной пирамиды?", "У пирамиды одно основание плюс треугольные боковые грани — по одной на каждую сторону основания.", ["7", "6", "8", "12"], "Шестиугольная пирамида имеет 1 шестиугольное основание + 6 треугольных боковых граней = 7 граней."],
    "TSR3_11": ["Сколько ребер у шестиугольной пирамиды?", "Подсчитайте ребра основания и ребра от каждой базовой вершины до вершины.", ["12", "6", "8", "18"], "Шестиугольная пирамида имеет 6 рёбер в основании + 6 боковых рёбер к вершине = 12 рёбер."],
    "TSR3_12": ["Сколько вершин имеет шестиугольная пирамида?", "Подсчитайте вершины основания и одну вершину.", ["7", "6", "8", "12"], "Шестиугольная пирамида имеет 6 вершин в основании + 1 вершину = 7 вершин. (Проверьте: 7 − 12 + 7 = 2 ✓)"],
    "TSR3_13": ["Если разрезать куб от середины одного ребра прямо до середины противоположного параллельного ребра, какой формы может быть поперечное сечение?", "Разрез между двумя параллельными краями дает плоский четырехугольник.", ["Прямоугольник", "Треугольник", "Пентагон", "Круг"], "Плоскость, проходящая через середины двух противоположных параллельных ребер, образует прямоугольное поперечное сечение."],
    "TSR3_14": ["Сколько граней у пятиугольной пирамиды с основанием?", "1 основание + боковые грани (по одному на каждый край основания).", ["6", "5", "7", "10"], "Пятиугольная пирамида имеет 1 пятиугольное основание + 5 треугольных сторон = 6 граней."],
    "TSR3_15": ["Сколько ребер у пирамиды с пятиугольным основанием?", "Формула ребра пирамиды: 2n ребер для n-стороннего основания.", ["10", "5", "8", "15"], "Пятиугольная пирамида имеет 5 рёбер в основании + 5 боковых рёбер = 10 рёбер."],
    "TSR3_16": ["Сколько вершин имеет пятиугольная пирамида с основанием?", "Пики основания плюс одиночная вершина.", ["6", "5", "7", "10"], "Пятиугольная пирамида имеет 5 вершин в основании + 1 вершину = 6 вершин. (Проверьте: 6 − 10 + 6 = 2 ✓)"],
    "TSR3_17": ["Используя формулу Эйлера (V − E + F = 2), сколько у многогранника граней, если у него 5 вершин и 8 ребер?", "Решите для F: F = 2 − V + E.", ["5", "4", "6", "7"], "F = 2 − 5 + 8 = 5. (Это описывает квадратную пирамиду: 5 вершин, 8 ребер, 5 граней.)"],
    "TSR3_18": ["Сколько диагоналей имеет правильный шестиугольник?", "Диагональная формула n-стороннего многоугольника: n(n - 3)/2.", ["9", "6", "12", "3"], "Диагонали = 6 × (6 − 3)/2 = 6 × 3/2 = 9."],
    "TSR3_19": ["Каково общее количество нарисованных граней в раскрашенном кубе 3×3×3, разрезанном на 27 маленьких кубиков, всего на 8 угловых кубиках?", "У каждого углового куба ровно три закрашенные грани.", ["24", "8", "12", "18"], "8 угловых кубиков × 3 нарисованных грани каждый = 24 нарисованных грани в углах."],
    "TSR3_20": ["Сколько диагоналей имеет правильный пятиугольник?", "Используйте n(n - 3)/2 с n = 5.", ["5", "4", "6", "3"], "Диагонали = 5 × (5 − 3)/2 = 5 × 2/2 = 5."],
    "TSR4_01": ["Куб размером 4х4х4 разрисован на всех гранях, затем разрезан на 64 маленьких кубика. Сколько маленьких кубиков имеют хотя бы одну закрашенную грань?", "Неокрашенная внутренняя часть образует меньший куб со стороной (4 - 2) = 2.", ["56", "48", "52", "60"], "Внутренние кубики с 0 красками = 2³ = 8. Таким образом, кубики хотя бы с одной нарисованной гранью = 64 − 8 = 56."],
    "TSR4_02": ["Раскрашенный кубик 4×4×4 разрезан на 64 маленьких кубика. Сколько маленьких кубиков имеют хотя бы две закрашенные грани?", "Это угловые кубики (3 стороны) и реберные кубики (2 стороны). Соберите их.", ["32", "24", "36", "28"], "Углы: 8 кубиков. Ребра: 12 ребер × 2 средних кубика = 24. Итого: 8 + 24 = 32."],
    "TSR4_03": ["Раскрашенный кубик 4×4×4 разрезан на 64 маленьких кубика. Каково общее количество закрашенных граней во всех 64 маленьких кубиках?", "Каждая из 6 исходных граней представляет собой сетку нарисованных граней 4×4.", ["96", "64", "72", "108"], "6 граней × 16 окрашенных единичных граней на грань = 96. (Проверьте: 8×3 + 24×2 + 24×1 = 24 + 48 + 24 = 96 ✓)"],
    "TSR4_04": ["Раскрашенный кубик 4×4×4 разрезан на 64 маленьких кубика. Сколько маленьких кубиков имеют не более 1 закрашенной грани?", "Соберите кубики с 0 нарисованными гранями и кубики с ровно 1.", ["32", "24", "28", "36"], "0 крашеных: 8 (внутренние 2×2×2). 1 окрашенный: 24 (центры граней). Итого: 8+24=32."],
    "TSR4_05": ["Если удалить один угловой куб из куба 3×3×3, сколько граней единичного куба будет видно на оставшемся теле (включая нижнюю часть)?", "При удалении угла теряются 3 внешние грани, но открываются 3 ранее скрытые внутренние грани.", ["54", "51", "57", "48"], "Исходная поверхность: 6 × 9 = 54. Удаление угла: −3 внешних + 3 вновь открытых внутренних = чистое изменение 0. Все еще 54."],
    "TSR4_06": ["Сколько диагоналей у правильного восьмиугольника?", "Используйте формулу n(n − 3)/2 при n = 8.", ["20", "16", "24", "8"], "Диагонали = 8 × (8 − 3)/2 = 8 × 5/2 = 20."],
    "TSR4_07": ["Сколько пространственных диагоналей имеет куб? (Диагональ пространства проходит через внутреннюю часть от одной вершины к противоположной вершине.)", "Куб имеет 8 вершин. Каждое диагональное пространство соединяет вершину с ее противоположностью.", ["4", "6", "8", "12"], "Куб имеет 4 пространственные диагонали. Каждый соединяет вершину с вершиной, расположенной по диагонали напротив центра."],
    "TSR4_08": ["Сколько всего диагоналей у куба?", "Каждое лицо представляет собой квадрат. Сколько диагоналей у квадрата? Умножьте на количество граней.", ["12", "6", "8", "24"], "Каждая из 6 граней имеет по 2 диагонали: 6×2 = 12 диагоналей грани."],
    "TSR4_09": ["Сколько граней имеет правильный октаэдр (две квадратные пирамиды между основаниями)?", "Каждая пирамида имеет 4 треугольные грани. Общее квадратное основание является внутренним.", ["8", "6", "12", "20"], "Правильный октаэдр имеет 8 равносторонних треугольных граней."],
    "TSR4_10": ["Сколько ребер у правильного октаэдра?", "Используйте формулу Эйлера, если знаете V = 6 и F = 8.", ["12", "8", "6", "24"], "По формуле Эйлера: E = V + F − 2 = 6 + 8 − 2 = 12 ребер."],
    "TSR4_11": ["Сколько вершин имеет правильный октаэдр?", "Представьте себе, что это две пирамиды, соединенные в основании. Отчетливо посчитайте пики.", ["6", "8", "12", "4"], "4 вершины вокруг общего квадратного экватора + 1 верхняя вершина + 1 нижняя вершина = 6 вершин."],
    "TSR4_12": ["Если 8 единичных кубов расположены в кубе 2×2×2, сколько граней единичного куба видно снаружи (включая нижнюю часть)?", "В результате получается больший куб со стороной 2. Какова площадь поверхности куба 2×2×2 в единицах граней?", ["24", "28", "32", "20"], "Куб 2×2×2 имеет площадь поверхности 6×(2×2) = 24 единичных грани."],
    "TSR4_13": ["Правильный додекаэдр имеет 12 пятиугольных граней и 30 рёбер. По формуле Эйлера, сколько у него вершин?", "V = 2 + E − F.", ["20", "12", "24", "30"], "V = 2 + 30 − 12 = 20 вершин."],
    "TSR4_14": ["Правильный икосаэдр имеет 20 треугольных граней и 12 вершин. Сколько у него ребер?", "Примените формулу Эйлера: E = V + F − 2.", ["30", "20", "24", "36"], "E = 12 + 20 − 2 = 30 ребер."],
    "TSR4_15": ["Каково общее количество окрашенных граней в раскрашенном кубе размером 4×4×4 на 8 угловых кубиках вместе взятых?", "Каждый угловой куб всегда имеет ровно три закрашенные грани, независимо от размера куба.", ["24", "8", "12", "32"], "8 углов × 3 нарисованные грани = 24."],
    "TSR4_16": ["Каково общее количество нарисованных граней в нарисованном кубе 4×4×4 только на реберных кубиках (в тех, у которых ровно две нарисованные грани)?", "Сначала найдите количество реберных кубиков, затем умножьте на 2.", ["48", "24", "36", "60"], "Имеется 24 реберных кубика (по 12 ребер × 2), каждый с 2 ​​закрашенными гранями: 24 × 2 = 48."],
    "TSR4_17": ["Если разрезать куб плоскостью, проходящей через середины трех ребер, сходящихся в одной вершине, какой формы будет поперечное сечение?", "Три средние точки равноудалены от угла. У какого треугольника все стороны равны?", ["Равносторонний треугольник", "Квадрат", "Прямоугольный треугольник", "Правильный шестиугольник"], "Плоскость одинаково пересекает три края в углу, образуя равносторонний треугольник."],
    "TSR4_18": ["Сколько диагоналей имеет правильный десятиугольник (10 сторон)?", "Диагональная формула: n(n − 3)/2.", ["35", "30", "40", "25"], "Диагонали = 10 × (10 − 3)/2 = 10 × 7/2 = 35."],
    "TSR4_19": ["Призма имеет ровно 10 вершин. Какова форма его основания?", "Призма с n-сторонним основанием имеет 2n вершин.", ["Пентагон", "Квадрат", "Шестиугольник", "Треугольник"], "2n = 10, значит, n = 5. Основание — пятиугольник."],
    "TSR4_20": ["У пирамиды ровно 7 граней. Какова форма его основания?", "Пирамида с n-гранным основанием имеет n+1 граней.", ["Шестиугольник", "Пентагон", "Семиугольник", "Октагон"], "n + 1 = 7, значит, n = 6. Основание — шестиугольник."],
    "TSR5_01": ["Куб размером 5х5х5 раскрашивается на всех гранях, затем разрезается на 125 маленьких кубиков. Сколько маленьких кубиков имеют ровно две закрашенные грани?", "Реберные кубы (не углы) имеют две закрашенные грани. Формула: 12(n - 2).", ["36", "24", "48", "30"], "12 ребер × (5 − 2) = 12 × 3 = 36 кубиков ровно с двумя закрашенными гранями."],
    "TSR5_02": ["Куб 5х5х5 разрисован на всех гранях и разрезан на 125 маленьких кубиков. Сколько маленьких кубиков имеют ровно три закрашенные грани?", "Только угловые кубики имеют три раскрашенные грани. Сколько углов у любого куба?", ["8", "12", "20", "6"], "Куб всегда имеет 8 углов, независимо от размера. Значит, у 8 кубиков ровно 3 закрашенные грани."],
    "TSR5_03": ["Раскрашенный кубик 5х5х5 разрезан на 125 маленьких кубиков. Сколько маленьких кубиков имеют хотя бы одну закрашенную грань?", "Вычтите неокрашенные внутренние кубики: (n − 2)³.", ["98", "96", "100", "90"], "Внутренние кубики = (5 − 2)³ = 27. Минимум 1 раскрашенный = 125 − 27 = 98."],
    "TSR5_04": ["Раскрашенный кубик 5х5х5 разрезан на 125 маленьких кубиков. Каково общее количество закрашенных граней во всех кубах?", "Каждая из 6 исходных граней представляет собой сетку 5×5.", ["150", "125", "144", "162"], "6×25 = 150. (Проверьте: 8×3 + 36×2 + 54×1 + 27×0 = 24 + 72 + 54 = 150 ✓)"],
    "TSR5_05": ["Куб размером 6×6×6 разрисован на всех гранях и разрезан на 216 маленьких кубиков. У скольких именно 2 нарисованных лица?", "Используйте 12(n - 2) с n = 6.", ["48", "36", "60", "24"], "12 × (6 − 2) = 12 × 4 = 48."],
    "TSR5_06": ["Куб размером 6×6×6 разрисован на всех гранях и разрезан на 216 маленьких кубиков. У скольких из них ровно 1 разрисованное лицо?", "Используйте 6(n − 2)² с n = 6.", ["96", "72", "108", "84"], "6 × (6 − 2)² = 6 × 16 = 96."],
    "TSR5_07": ["Раскрашенный кубик 6х6х6 разрезан на 216 маленьких кубиков. У скольких вообще нет накрашенного лица?", "Внутренний блок равен (n − 2)³.", ["64", "48", "36", "27"], "(6 − 2)³ = 4³ = 64 кубика без краски."],
    "TSR5_08": ["Раскрашенный кубик 6х6х6 разрезан на 216 маленьких кубиков. У скольких из них ровно три нарисованных лица?", "Угловые кубы всегда имеют одинаковый номер, независимо от размера куба.", ["8", "12", "6", "24"], "Куб всегда имеет ровно 8 углов. Итак, у 8 кубиков 3 закрашенные грани. (Проверьте: 8 + 48 + 96 + 64 = 216 ✓)"],
    "TSR5_09": ["Раскрашенный кубик 6х6х6 разрезан на 216 маленьких кубиков. Каково общее количество закрашенных граней во всех кубах?", "Каждая исходная грань представляет собой сетку единичных граней 6×6.", ["216", "200", "192", "240"], "6 × 36 = 216. (Проверьте: 8 × 3 + 48 × 2 + 96 × 1 = 24 + 96 + 96 = 216 ✓)"],
    "TSR5_10": ["Сколько из раскрашенных кубиков размером 10×10×10, разрезанных на 1000 маленьких кубиков, имеют ровно две закрашенные грани?", "Формула: 12(n - 2) для реберных кубов.", ["96", "120", "80", "108"], "12 × (10 − 2) = 12 × 8 = 96."],
    "TSR5_11": ["Сколько маленьких кубиков в раскрашенном кубе размером 10×10×10 имеют ровно одну раскрашенную грань?", "Формула: 6(n - 2)² для кубов с гранью-центром.", ["384", "360", "400", "480"], "6 × (10 − 2)² = 6 × 64 = 384."],
    "TSR5_12": ["Сколько маленьких кубиков в раскрашенном кубе размером 10×10×10 вообще не имеют раскрашенной грани?", "Неокрашенная внутренность представляет собой куб со стороной (n − 2).", ["512", "480", "500", "343"], "(10 − 2)³ = 8³ = 512. (Проверьте: 8 + 96 + 384 + 512 = 1000 ✓)"],
    "TSR5_13": ["Какую из этих фигур МОЖНО получить в виде сечения куба?", "Плоскость может пересекать до шести граней куба. Подумайте о симметрии: сможете ли вы разрезать 6 средних точек ребра?", ["Правильный шестиугольник", "Правильный пятиугольник", "Правильный восьмиугольник", "Эллипс"], "Разрезав куб по средним точкам шести ребер, получим правильный шестиугольник. Симметрия куба не может создавать пятикратные формы, восьмиугольники (максимум 6 сторон) или кривые."],
    "TSR5_14": ["Какое максимальное количество сторон может иметь поперечное сечение куба?", "Многоугольник поперечного сечения получает одну сторону для каждой грани, которую пересекает секущая плоскость.", ["6", "4", "8", "12"], "У куба 6 граней. Плоскость может пересечь все 6, образуя не более шестиугольника (6 сторон)."],
    "TSR5_15": ["Правильный додекаэдр имеет 12 пятиугольных граней. Каждая грань имеет 5 ребер, но каждое ребро является общим для двух граней. Сколько у него ребер?", "Общее количество реберных слотов = 12 × 5, но каждое ребро учитывается дважды.", ["30", "24", "36", "60"], "Ребра = 12×5/2 = 30."],
    "TSR5_16": ["Сколько из раскрашенных кубиков размером 7×7×7, разрезанных на 343 маленьких кубика, имеют ровно две раскрашенные грани?", "Примените 12(n − 2) с n = 7.", ["60", "48", "72", "36"], "12 × (7 − 2) = 12 × 5 = 60."],
    "TSR5_17": ["Сколько маленьких кубиков в раскрашенном кубе размером 7×7×7 не имеют закрашенной грани?", "Внутренность куба: (n − 2)³.", ["125", "64", "100", "27"], "(7 − 2)³ = 5³ = 125."],
    "TSR5_18": ["Для окрашенного куба размера n×n×n количество маленьких кубиков ровно с одной нарисованной гранью равно 6(n − 2)². Для какого значения n это равно 96?", "Решите 6(n − 2)² = 96 → (n − 2)² = 16.", ["6", "5", "7", "8"], "6(n − 2)² = 96 → (n − 2)² = 16 → n − 2 = 4 → n = 6."],
    "TSR5_19": ["Какое максимальное количество сторон может иметь поперечное сечение треугольной призмы?", "Треугольная призма имеет 5 граней (2 треугольника + 3 прямоугольника). Может ли одна плоскость пересекать все пять?", ["5", "4", "3", "6"], "Плоскость, наклоненная так, чтобы пересечь оба треугольных основания и все три прямоугольные грани, дает пятиугольное поперечное сечение — максимум 5."],
    "TSR5_20": ["Каково общее количество нарисованных единичных граней в раскрашенном кубе размером 7×7×7 во всех 343 маленьких кубиках?", "Каждая из 6 исходных граней представляет собой сетку 7×7.", ["294", "252", "300", "343"], "6 × 49 = 294. (Проверьте: 8 × 3 + 60 × 2 + 150 × 1 + 125 × 0 = 24 + 120 + 150 = 294 ✓)"],
    "TMP1_1": ["У фермера 12 овец. Все, кроме пяти, умирают. Сколько овец у него осталось?", "Сосредоточьтесь на фразе «все, кроме 5».", ["5", "7", "12", "0"], "«Все, кроме пяти, умрут» означает, что пятеро выживут. Ответ 5, а не 12 минус 5."],
    "TMP1_2": ["Вы обгоняете человека, занявшего 3-е место в гонке. В каком месте ты сейчас находишься?", "Подумайте, что происходит, когда вы кого-то обгоняете — чью позицию вы занимаете?", ["3-й", "2-й", "4-й", "1-й"], "Когда вы пропускаете человека на 3-е место, вы занимаете его позицию и становитесь 3-м, а не 2-м местом."],
    "TMP1_3": ["Сколько дней рождения у среднестатистического человека?", "Вы рождаетесь только один раз.", ["1", "Около 75", "365", "Это зависит от возраста"], "У каждого ровно один день рождения — день, когда он родился. Остальные имеют юбилеи этого дня."],
    "TMP1_4": ["Если у вас 5 апельсинов и вы берёте 2, сколько апельсинов у вас?", "Кто именно взял апельсины?", ["2", "3", "5", "0"], "Вы взяли 2 апельсина — значит, у вас их 2. Вопрос о том, сколько апельсинов у вас, а не сколько осталось у других или в корзине."],
    "TMP1_5": ["А — отец Б, но Б не является сыном А. Как это возможно?", "Рассмотрим все возможные полы Б.", ["Б — дочь А", "А на самом деле не отец Б", "Б принят", "У них есть сводные родственники"], "Б — женщина, она дочь А. Не каждый ребенок — мальчик."],
    "TMP1_6": ["Сколько раз можно вычесть 10 из 100?", "После первого вычитания останется ли оно 100?", ["1", "10", "9", "бесконечный"], "Только один раз — после первого вычитания у вас есть 90, поэтому вы вычитаете 10 из 90, а не из 100."],
    "TMP1_7": ["Если петух снесёт яйцо на конёк крыши, в какую сторону оно покатится?", "Кто несёт яйца у кур?", ["Петухи не несут яиц", "Влево", "Вправо", "Останется на вершине"], "Петухи яиц не несут — вопрос с невозможной посылкой."],
    "TMP1_8": ["Что весит больше: фунт перьев или фунт кирпичей?", "Сравните массу, а не объём.", ["Одинаково (по фунту)", "Кирпичи тяжелее", "Перья тяжелее", "Зависит от влажности"], "Фунт — одна и та же единица массы; масса одинакова."],
    "TMP1_9": ["Изначально рубашка стоит 50 долларов и продается со скидкой 50%. Сколько вы платите?", "Рассчитайте 50% от первоначальной цены.", ["$25", "$50", "$30", "$15"], "50% от 50 долларов = 25 долларов. Вы платите 25 долларов."],
    "TMP1_10": ["Вы находитесь в темной комнате со свечой, масляной лампой и камином. У вас есть один матч. Что вы зажигаете первым?", "Вам нужно что-то зажечь, прежде чем что-то еще сможет сработать.", ["Матч", "Свеча", "Масляная лампа", "Камин"], "Сначала вы должны зажечь спичку, прежде чем сможете использовать ее для зажигания чего-либо еще."],
    "TMP1_11": ["Самолет терпит крушение ровно на границе двух стран. Где хоронить выживших?", "Прочтите внимательно вопрос — кого именно хороним?", ["Вы не хороните выживших", "В стране отправления", "В стране назначения", "На границе"], "Выжившие живы — живых людей не хоронят."],
    "TMP1_12": ["Сколько животных каждого вида взял Моисей в ковчег?", "Внимательно проверьте имя в вопросе.", ["Нет — это был Ной, а не Моисей.", "2", "7", "1"], "У Моисея не было ковчега — это был Ной. В вопросе используется неправильное имя, чтобы обмануть вас."],
    "TMP1_13": ["На заборе сидят 10 птиц. Вы стреляете в одного. Сколько осталось на заборе?", "Подумайте, как другие птицы отреагируют на выстрел.", ["0", "9", "10", "1"], "Выстрел отпугивает остальных. На заборе не осталось ни одной птицы."],
    "TMP1_14": ["У фермера 20 коров. Все, кроме 12, умирают. Сколько ему осталось?", "Сосредоточьтесь на фразе «все, кроме 12».", ["12", "8", "20", "0"], "«Все, кроме 12, умрут» означает, что 12 выживут."],
    "TMP1_15": ["Что идет вверх, но никогда не следует вниз?", "Подумайте о чем-то, что со временем только увеличивается.", ["Ваш возраст", "Воздушный шар", "Солнце", "температура"], "Ваш возраст только увеличивается и никогда не уменьшается."],
    "TMP1_16": ["Девушка пинает футбольный мяч на расстоянии 10 футов. Он следует обратно к ней без стены, без другого человека и без вращения. Как?", "Подумайте, в каком направлении она его пнула.", ["Она пнула его прямо вверх", "Ветер унес его обратно", "Он отскочил от дерева", "Земля была с уклоном"], "Она подбросила мяч прямо в воздух, и гравитация вернула его обратно к ней."],
    "TMP1_17": ["Что имеет голову и хвост, но не имеет тела?", "Бытовой предмет, не животное.", ["Монета", "Змея", "Булавка", "Комета"], "У монеты есть «орёл» и «решка» (голова и хвост), тела как у зверя нет."],
    "TMP1_18": ["Врач даёт 5 таблеток: по одной каждый час. За сколько часов вы примете все?", "Между первой и пятой таблеткой сколько интервалов по часу?", ["4 часа", "5 часов", "6 часов", "3 часа"], "1-я в момент 0, 5-я через 4 часа после первой — прошло 4 часа."],
    "TMP1_19": ["Если у вас есть миска с 6 яйцами и вы достаете 2, сколько их у вас будет?", "У кого есть яйца, которые вы взяли?", ["2", "4", "6", "0"], "Вы взяли 2 яйца, значит, у вас их 2. В миске по-прежнему 4, но вопрос в том, сколько их у вас."],
    "TMP1_20": ["Мальчику 4 года, а его сестра вдвое моложе его. Когда мальчику исполнится 100 лет, сколько лет будет его сестре?", "Сколько между ними постоянная разница в возрасте?", ["98", "50", "100", "96"], "Сестра младше на 2 года (4 ÷ 2 = 2). Разница в возрасте остается прежней: 100 − 2 = 98."],
    "TMP2_1": ["Ручка и блокнот вместе стоят 1,10 доллара. Блокнот стоит на 1 доллар дороже ручки. Сколько стоит ручка?", "Если ручка стоит x, блокнот стоит x + 1 доллар. Составьте уравнение.", ["$0.05", "$0.10", "$1.00", "$0.50"], "Пусть ручка = x, блокнот = x + 1. Тогда x + (x + 1) = 1,10 → 2x = 0,10 → x = 0,05 доллара."],
    "TMP2_2": ["Врач дает вам 3 таблетки и говорит принимать по одной каждые 45 минут. Как долго действуют таблетки?", "Когда вы примете первую таблетку?", ["90 минут", "135 минут", "45 минут", "120 минут"], "Место 1 на 0 минуте, место 2 на 45 минуте, место 3 на 90 минуте. Всего прошло: 90 минут."],
    "TMP2_3": ["Если 5 рабочих могут построить 5 стен за 5 дней, сколько времени понадобится 10 рабочим, чтобы построить 10 стен?", "Сколько времени нужно одному рабочему, чтобы построить одну стену?", ["5 дней", "10 дней", "2,5 дня", "1 день"], "Каждый рабочий строит 1 стену за 5 дней. Если 10 рабочих строят 10 стен, каждая из них по-прежнему занимает 5 дней."],
    "TMP2_4": ["Две монеты в сумме составляют 30 центов. Один из них не пятак. Какие две монеты?", "В заявлении говорится, что ОДИН из них не никель, а как насчет другого?", ["Четверть и никель", "Две копейки", "Полдоллара", "Десять центов и никель"], "«Один из них не пятак» — это четвертак (25 центов). Другой — никель (5 центов). Итого: 30 центов."],
    "TMP2_5": ["Умножьте все цифры на клавиатуре телефона (от 0 до 9). Чему равно произведение?", "Среди множителей есть особая цифра.", ["0", "3 628 800", "362 880", "45"], "В произведении есть множитель 0 — произведение равно 0."],
    "TMP2_6": ["В семье 4 мальчика и 3 девочки. У каждого мальчика столько же сестер, сколько и братьев. У каждой девочки в два раза больше братьев, чем сестер. Сколько там детей?", "Посчитайте братьев и сестер с точки зрения каждого ребенка.", ["7", "8", "6", "10"], "У каждого мальчика есть 3 брата и 3 сестры ✓. У каждой девочки есть 4 брата и 2 сестры (4 = 2×2) ✓. Итого: 4+3=7."],
    "TMP2_7": ["Электропоезд движется на север. Ветер дует на запад. В каком направлении идет дым?", "Какую энергию использует этот поезд?", ["Там нет курения", "Запад", "Север", "Восток"], "Электропоезда не сжигают топливо и не выделяют дыма."],
    "TMP2_8": ["Если 8 человек могут построить стену за 10 часов, сколько времени понадобится 4 человека, чтобы построить такую ​​же стену?", "Уменьшение количества рабочих вдвое удваивает время.", ["20 часов", "5 часов", "40 часов", "10 часов"], "Половина рабочих = двойное время. 10 × 2 = 20 часов."],
    "TMP2_9": ["Сколько месяцев в году имеют 30 дней?", "Подумайте внимательно: в некоторых месяцах БОЛЬШЕ 30 дней?", ["11", "4", "6", "7"], "Во всех месяцах не менее 30 дней, кроме февраля (28 или 29). Итак, в 11 месяцах 30 дней."],
    "TMP2_10": ["Вы копаете 6 ям: 3 большие и 3 маленькие. Сколько у тебя дырок?", "Изменяет ли размер отверстия то, что оно есть?", ["6", "3", "9", "0"], "Дыра есть дыра независимо от размера. Выкопаете 6 ям, и у вас будет 6 ям."],
    "TMP2_11": ["Можете ли вы назвать три дня подряд, не используя понедельник, вторник, среду, четверг, пятницу, субботу или воскресенье?", "Думайте о днях, а не об именах собственных.", ["Вчера, сегодня и завтра", "День 1, День 2, День 3", "Это невозможно", "Утро, день, вечер"], "Вчера, сегодня и завтра всегда три дня подряд."],
    "TMP2_12": ["Сколько будет 1/2 от 2/3 от 3/4 от 4/5 от 100?", "Попробуйте упростить дроби шаг за шагом, прежде чем умножать.", ["20", "10", "50", "25"], "Дроби упрощаются: 1/2×2/3×3/4×4/5 = 1/5. Тогда 1/5 × 100 = 20."],
    "TMP2_13": ["Водяная лилия увеличивается в размерах вдвое каждый день. Если на 20-й день оно полностью заполнило пруд, то в какой день оно составило ровно 25% пруда?", "Это работает наоборот: если он удваивается каждый день, то в обратном порядке уменьшайте его вдвое.", ["День 18", "День 5", "День 15", "День 10"], "День 20: 100%. День 19: 50%. День 18: 25%. Два даблинга назад от фулла."],
    "TMP2_14": ["Кирпич весит 1 кг плюс полкирпича. Насколько тяжел кирпич?", "Составьте уравнение: пусть b = вес кирпича.", ["2 кг", "1,5 кг", "3 кг", "1 кг"], "b = 1 + b/2 → b/2 = 1 → b = 2 кг."],
    "TMP2_15": ["Если 6 человек выкопают 6 ям за 6 часов, то сколько времени понадобится 3 человекам, чтобы выкопать 3 ямы?", "За какое время один человек выкопает одну яму?", ["6 часов", "3 часа", "12 часов", "9 часов"], "Каждый человек роет 1 яму за 6 часов. По 3 человека роют по 1 яме — еще 6 часов."],
    "TMP2_16": ["Какая следующая буква в ряду: O, T, T, F, F, S, S, ?", "Первые буквы английских слов числительных: One, Two, Three, Four, Five, Six, Seven, Eight…", ["E", "N", "T", "H"], "One, Two, Three, Four, Five, Six, Seven, Eight — дальше буква E."],
    "TMP2_17": ["У вас есть 8 мячей. Семь весят одинаково, а один тяжелее. Каково минимальное количество взвешиваний, чтобы найти на весах более тяжелое?", "Разделите шары на три группы, а не на две.", ["2", "3", "1", "4"], "Взвесьте 3 против 3. Если они равны, взвесьте оставшиеся 2. Если неравны, возьмите более тяжелую группу и взвесьте 1 против 1. Всегда 2 взвешивания."],
    "TMP2_18": ["В гонке вы обгоняете человека, занявшего последнее место. В каком положении вы сейчас находитесь?", "Подумайте, кто стоит за человеком, занимающим последнее место.", ["Это невозможно", "последнее место", "Предпоследний", "Первое место"], "Никто не стоит за человеком, занявшим последнее место. Если бы вы были позади них, вы были бы на последнем месте — поэтому вы не сможете их обойти."],
    "TMP2_19": ["Если 3 кошки поймают 3 мышей за 3 минуты, сколько времени понадобится 100 кошкам, чтобы поймать 100 мышей?", "За сколько минут каждая кошка ловит одну мышь?", ["3 минуты", "100 минут", "33 минуты", "1 минута"], "Каждая кошка ловит 1 мышь за 3 минуты. 100 кошек параллельно ловят 100 мышей — еще 3 минуты."],
    "TMP2_20": ["Какую часть суток составляют 6 часов?", "Сколько часов в полном дне?", ["1/4", "1/6", "1/3", "1/2"], "В сутках 24 часа. 6 ÷ 24 = 1/4."],
    "TMP3_1": ["Если 6 машин изготавливают 6 игрушек за 6 минут, сколько времени потребуется 12 машинам, чтобы изготовить 12 игрушек?", "За сколько минут каждая машина изготавливает одну игрушку?", ["6 минут", "12 минут", "3 минуты", "1 минута"], "Каждая машина изготавливает 1 игрушку за 6 минут. 12 машин делают 1 игрушку за 6 минут — еще 6 минут в сторону."],
    "TMP3_2": ["Часы показывают 6:00. Каков угол между часовой и минутной стрелками?", "Куда указывают стрелки ровно в 6:00?", ["180°", "90°", "120°", "360°"], "В 6:00 минутная стрелка указывает на 12, а часовая — на 6 — прямая линия в 180°."],
    "TMP3_3": ["Часы показывают 9:00. Каков угол между часовой и минутной стрелками?", "Куда указывают стрелки ровно в 9:00?", ["90°", "180°", "270°", "45°"], "В 9:00 минутная стрелка указывает на 12, а часовая — на 9 — прямой угол 90°."],
    "TMP3_4": ["В числовой сетке действует правило: столбец 1 + столбец 2 = столбец 3. Строки: [3, 5, 8], [7, 2, 9], [4, 6, ?]. Найдите недостающее числовое значение.", "Примените то же правило сложения к третьей строке.", ["10", "8", "12", "6"], "Следуя правилу: 4+6=10."],
    "TMP3_5": ["В числовой сетке действует правило: столбец 1 × столбец 2 = столбец 3. Строки: [2, 5, 10], [3, 4, 12], [6, 3, ?]. Найдите недостающее числовое значение.", "Умножьте первые два столбца третьей строки.", ["18", "9", "15", "21"], "Следуя правилу: 6×3=18."],
    "TMP3_6": ["Улитка днем ​​поднимается на 4 метра, а ночью скатывается на 2 метра. Стена высотой 12 метров. Сколько дней нужно, чтобы достичь вершины?", "В последний день улитка достигает вершины и не соскальзывает назад.", ["5 дней", "6 дней", "4 дня", "10 дней"], "Каждый полный цикл день-ночь: нетто +2м. Через 4 дня: 8м. На 5-й день улитка поднимается на высоту 8+4=12м — вершины она достигает еще до наступления темноты."],
    "TMP3_7": ["Если 2 человека могут покрасить 2 комнаты за 2 часа, сколько времени понадобится 4 человекам, чтобы покрасить 4 комнаты?", "За сколько часов каждый человек красит одну комнату?", ["2 часа", "4 часа", "1 час", "8 часов"], "Каждый человек красит 1 комнату за 2 часа. 4 человека красят параллельно 4 комнаты — еще 2 часа."],
    "TMP3_8": ["Вы покупаете товар за 3 доллара и продаете его за 5 долларов. Затем вы покупаете еще один товар за 6 долларов и продаете его за 9 долларов. Какова ваша общая прибыль?", "Рассчитайте прибыль от каждой сделки отдельно.", ["$5", "$3", "$2", "$6"], "Первая сделка: $5 − $3 = прибыль $2. Вторая сделка: $9 − $6 = $3 прибыли. Итого: 2 доллара + 3 доллара = 5 долларов."],
    "TMP3_9": ["Лягушка за каждый цикл прыгает на 3 метра вперед, а затем скользит на 1 метр назад. Сколько прыжков ему нужно, чтобы преодолеть расстояние более 10 метров?", "В последнем прыжке лягушка минует цель, не соскальзывая назад.", ["5 прыжков", "4 прыжка", "6 прыжков", "10 прыжков"], "После 4 циклов: 4×2=8м. В прыжке 5: 8 + 3 = 11 м, что превышает 10 м. Итак 5 прыжков."],
    "TMP3_10": ["Том в 3 раза старше Джима. Через 10 лет Том будет вдвое старше Джима. Сколько лет Джиму сейчас?", "Составьте два уравнения: T = 3J и T + 10 = 2(J + 10).", ["10", "5", "15", "20"], "Т = 3Дж. Через 10 лет: 3J + 10 = 2(J + 10) → 3J + 10 = 2J + 20 → J = 10."],
    "TMP3_11": ["Купите лошадь за 60 долларов, продайте ее за 70 долларов, выкупите ее обратно за 80 долларов и снова продайте за 90 долларов. Какова ваша общая прибыль?", "Отслеживайте прибыль или убыток каждой транзакции отдельно.", ["$20", "$10", "$30", "$0"], "Первая сделка: 70$ − 60$ = +10$. Вторая сделка: 90$ − 80$ = +10$. Общая прибыль: 20 долларов."],
    "TMP3_12": ["Если сложить лист бумаги пополам 7 раз, сколько слоев он будет иметь?", "Каждая складка удваивает количество слоев.", ["128", "64", "14", "256"], "Каждая складка удваивает слои: 2⁷ = 128."],
    "TMP3_13": ["Простое число, умноженное само на себя, равно 169. Что такое простое число?", "Найдите квадратный корень из 169.", ["13", "11", "17", "7"], "√169 = 13, а 13 действительно простое число."],
    "TMP3_14": ["Два поезда на расстоянии 100 миль, каждый со скоростью 50 миль/ч навстречу друг другу. Муха летит между ними со скоростью 75 миль/ч. Какой путь пролетит муха до встречи поездов?", "Сначала время до столкновения поездов.", ["75 миль", "100 миль", "50 миль", "150 миль"], "Сближение 100 миль/ч → встреча через 1 ч. Муха: 75 миль/ч × 1 ч = 75 миль."],
    "TMP3_15": ["Какое наименьшее число делится без остатка на любое целое число от 1 до 6?", "Найдите наименьшее общее кратное (НОК) чисел 1, 2, 3, 4, 5 и 6.", ["60", "30", "120", "720"], "НОК(1,2,3,4,5,6) = 60. Проверьте: 60 ÷ 1, 2, 3, 4, 5, 6 — все дают целые числа."],
    "TMP3_16": ["Если считать от 1 до 100, сколько раз появится цифра 7?", "Посчитайте появления в разряде единиц и десятков отдельно.", ["20", "10", "11", "19"], "Единицы типа: 7, 17, 27, ..., 97 = 10 раз. Десятки: 70, 71, ..., 79 = 10 раз. Всего: 20."],
    "TMP3_17": ["Число, увеличенное на 20%, становится 60. Каким было исходное число?", "Если число х, то 1,2х = 60.", ["50", "48", "72", "40"], "1,2х = 60 → х = 60 ÷ 1,2 = 50."],
    "TMP3_18": ["Если сложить лист бумаги пополам 10 раз, сколько слоев он будет иметь?", "Каждая складка удваивает количество слоев.", ["1024", "100", "512", "2048"], "2¹⁰ = 1024 слоя."],
    "TMP3_19": ["Произведение двух последовательных положительных целых чисел равно 156. Каковы эти два целых числа?", "Найдите два соседних целых числа, произведение которых равно 156.", ["12 и 13", "11 и 12", "13 и 14", "10 и 15"], "12 × 13 = 156. Они имеют последовательные целые числа."],
    "TMP3_20": ["В магическом квадрате 3×3 сумма в каждой строке, столбце и диагонали равна 15. Верхний ряд [2, 7, 6], средний [9, 5, 1]. Какое первое число в нижнем ряду?", "Сумма первого столбца = 15.", ["4", "3", "6", "8"], "2 + 9 + ? = 15 → ? = 4."],
    "TMP4_1": ["Колония бактерий удваивается каждый час и полностью заполняет банку в полдень. В какое время банка была заполнена на четверть?", "Это работает наоборот: если он удваивается каждый час, уменьшайте его вдвое с каждым шагом назад.", ["10:00 утра", "11:00", "9:00 утра", "6:00 утра"], "Полдень: 100%. 11:00: 50%. 10:00: 25%. Два часа до полудня."],
    "TMP4_2": ["У вас есть 24 монеты. Один поддельный и легче остальных. Каково минимальное количество взвешиваний на весах, чтобы гарантировать его нахождение?", "На каждом этапе разделите монеты на три группы.", ["3", "4", "5", "2"], "Разделите 24 монеты на группы по 8. Взвесьте 8 против 8 (найдите более лёгкую группу). Затем 3 против 3 внутри неё. Потом 1 против 1. Три взвешивания."],
    "TMP4_3": ["Веревку разрезаем на 3 части. Затем каждый кусок разрезается на 3 меньшие части. Сколько всего штук?", "Каждая из 3 оригинальных частей становится 3 частями.", ["9", "6", "12", "27"], "3 исходных детали × 3 дополнительных детали = всего 9 штук."],
    "TMP4_4": ["Червь находится на дне 30-метрового колодца. Днем он поднимается на 5 метров, а ночью опускается на 4 метра. Сколько дней нужно, чтобы достичь вершины?", "В последний день червь выходит из колодца и больше не скользит обратно.", ["26 дней", "30 дней", "25 дней", "27 дней"], "Чистая прибыль: 1 м за цикл день-ночь. Через 25 дней: 25м. День 26: 25+5=30м — вершина достигнута еще до ночи."],
    "TMP4_5": ["Если 8 человек могут построить стену за 10 дней, сколько дней понадобится 5 мужчинам, чтобы построить такую ​​же стену?", "Общий объем работы = количество человек × количество дней.", ["16 дней", "12 дней", "20 дней", "8 дней"], "Общий объем работ: 8×10 = 80 человеко-дней. Для 5 мужчин: 80 ÷ 5 = 16 дней."],
    "TMP4_6": ["Труба А наполняет резервуар за 6 часов. Труба B заполняет его за 3 часа. Сколько времени потребуется, чтобы наполнить резервуар с обеими открытыми трубами?", "Складываем ставки: 1/6 + 1/3 в час.", ["2 часа", "4,5 часа", "3 часа", "1,5 часа"], "Комбинированная ставка: 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2 в час. Время: 2 часа."],
    "TMP4_7": ["Длина прямоугольника в 3 раза больше его ширины. Его периметр составляет 48 метров. Какова его площадь?", "Пусть ширина = w, поэтому длина = 3w. Периметр = 2(w + 3w).", ["108 м²", "96 м²", "144 м²", "48 м²"], "2(ш + 3ш) = 48 → 8ш = 48 → ш = 6. Длина = 18. Площадь = 6 × 18 = 108 м²."],
    "TMP4_8": ["Число увеличивается на 20%, а затем уменьшается на 20%. Насколько чистое процентное изменение отличается от оригинала?", "Начните со 100 и последовательно примените оба процентных изменения.", ["снижение на 4%", "0% (без изменений)", "увеличение на 4%", "снижение на 2%"], "100 → +20% → 120 → −20% → 96. Чистое изменение: 96 − 100 = −4, что означает уменьшение на 4%."],
    "TMP4_9": ["Магазин поднимает все цены на 25%, а затем предлагает скидку 20%. Насколько чистое изменение цены отличается от первоначальной?", "Примените оба процентных изменения к стартовой цене в 100 долларов США.", ["0% (без изменений)", "5% увеличение", "снижение на 5%", "Увеличение на 45 %"], "1,25 × 0,80 = 1,00. Цена возвращается к исходной — чистое изменение 0%."],
    "TMP4_10": ["Какова сумма первых 20 натуральных чисел?", "Используйте формулу: n(n + 1)/2.", ["210", "200", "190", "220"], "Сумма = 20×21/2 = 210."],
    "TMP4_11": ["Каков угол между часовой и минутной стрелками часов в 4:30?", "В 4:30 часовая стрелка переместилась посередине между цифрами 4 и 5.", ["45°", "90°", "60°", "30°"], "Минутная стрелка на 180° (указывает на 6). Часовая стрелка на 135° (4 × 30° + 0,5 × 30°). Разница: 180° − 135° = 45°."],
    "TMP4_12": ["Автомобиль проехал 60 км со скоростью 30 км/ч, затем 60 км со скоростью 60 км/ч. Какова средняя скорость на всем пути?", "Средняя скорость = общее расстояние ÷ общее время (а не среднее из двух скоростей).", ["40 км/ч", "45 км/ч", "50 км/ч", "35 км/ч"], "Время 1: 60/30 = 2 часа. Время 2: 60/60 = 1 час. В среднем: 120 км/3 часа = 40 км/ч."],
    "TMP4_13": ["Если 2^10 = 1024, чему будет 2^12?", "2^12 = 2^10 × 2^2.", ["4096", "2048", "8192", "1248"], "2^12 = 1024 × 4 = 4096."],
    "TMP4_14": ["Кран наполняет бассейн за 4 часа. Дренаж опорожняет его за 8 часов. Когда оба открыты, как долго наполнять бассейн?", "Чистая скорость наполнения = скорость наполнения минус скорость дренажа.", ["8 часов", "6 часов", "12 часов", "4 часа"], "Скорость заполнения: 1/4 в час. Скорость слива: 1/8 в час. Чистое: 1/4 − 1/8 = 1/8 в час. Время: 8 часов."],
    "TMP4_15": ["Цена падает на 10%, затем падает еще на 10%. Каково общее процентное снижение первоначальной цены?", "Вторая скидка в размере 10 % применяется к уже сниженной цене.", ["19%", "20%", "18%", "21%"], "0,90 × 0,90 = 0,81. Общее падение: 1 − 0,81 = 0,19 = 19%."],
    "TMP4_16": ["Найдите х: 3х+7=22.", "Изолируйте x, отменив операции шаг за шагом.", ["5", "7", "3", "10"], "3x = 22 − 7 = 15. x = 15 ÷ 3 = 5."],
    "TMP4_17": ["Поезд длиной 100 метров движется со скоростью 50 м/с. Сколько времени нужно, чтобы полностью пройти столб?", "Весь поезд должен пройти через столб — ему нужно преодолеть свою длину.", ["2 секунды", "1 секунда", "4 секунды", "0,5 секунды"], "Время = расстояние/скорость = 100 м/50 м/с = 2 секунды."],
    "TMP4_18": ["Два рабочих вместе выполняют работу за 12 дней. Только на один из них уходит 20 дней. Сколько времени другой занимает один?", "Комбинированная ставка минус ставка одного работника дает ставку другого.", ["30 дней", "24 дня", "15 дней", "40 дней"], "1/12 – 1/20 = 5/60 – 3/60 = 2/60 = 1/30. Другой работник занимает 30 дней в одиночку."],
    "TMP4_19": ["Вы инвестируете 1000 долларов США под простые проценты 5% в год на срок 3 года. Сколько всего процентов вы зарабатываете?", "Простые проценты = основная сумма × ставка × время.", ["$150", "$1150", "$50", "$300"], "Проценты = 1000 долларов США × 0,05 × 3 = 150 долларов США."],
    "TMP4_20": ["У фермера есть куры и коровы. Всего 20 голов и 56 ног. Сколько здесь цыплят?", "Составьте два уравнения: одно для голов, другое для ног.", ["12", "8", "14", "10"], "c+w=20 и 2c+4w=56. Решение: w=8, c=12. Куриц 12."],
    "TMP5_1": ["У вас есть две верёвки. Каждая сгорает полностью ровно за 1 час, но неравномерно. Как отмерить ровно 45 минут?", "Что будет, если зажечь верёвку с обоих концов сразу?", ["Зажгите верёвку 1 с обоих концов и верёвку 2 с одного конца одновременно", "Зажгите обе верёвки с одного конца одновременно", "Разрежьте одну верёвку на четыре части и зажгите один кусок", "Зажгите одну верёвку, дождитесь конца, затем зажгите другую"], "Верёвка 1 (оба конца) сгорает за 30 мин. В этот момент зажгите второй конец верёвки 2 — ещё 15 мин. Итого: 45 мин."],
    "TMP5_2": ["Два отца и два сына садятся есть. Они едят ровно 3 яйца, причем каждый человек съедает ровно 1 яйцо. Как это возможно?", "Может ли один человек выполнять две роли одновременно?", ["Это дедушка, отец и сын (3 человека)", "Один человек вообще не ел", "Было 4 человека, но один поделился", "Кто-то съел два яйца"], "Три поколения: дедушка (отец), отец (и сын, и отец) и сын. Два отца + два сына = 3 человека."],
    "TMP5_3": ["В ряду стоит 100 шкафчиков, все закрыты. 100 учеников проходят последовательно: ученик k открывает каждый k-й шкафчик. Сколько шкафчиков открыто в конце?", "Шкафчик открывается только в том случае, если его переключить нечетное количество раз. Какие числа имеют нечетное число делителей?", ["10", "50", "25", "0"], "Только совершенные квадраты имеют нечетное количество делителей: 1, 4, 9, 16, 25, 36, 49, 64, 81, 100. Это 10 шкафчиков."],
    "TMP5_4": ["Три выключателя снаружи закрытой комнаты управляют тремя лампочками внутри. В комнату можно войти только один раз. Как определить, какой выключатель к какой лампочке относится?", "Лампочка, которая долго горела, останется тёплой после выключения.", ["Включите выключатель 1, подождите, выключите, включите выключатель 2, затем войдите: тёплая выкл. = 1, горит = 2, холодная выкл. = 3", "Щёлкайте каждым выключателем по очереди и каждый раз заходите проверять", "Быстро включите и выключите все три, затем войдите", "Смотрите в замочную скважину после каждого щелчка"], "Включите 1 на несколько минут, выключите, включите 2, войдите. Тёплая, но выключенная = 1. Горит = 2. Холодная и выключенная = 3."],
    "TMP5_5": ["Три коробки подписаны «Яблоки», «Апельсины» и «Смешанное». ВСЕ надписи неверны. Можно взять один фрукт из одной коробки. Из какой?", "Коробка «Смешанное» не может содержать смесь, если все ярлыки ложные.", ["Коробка «Смешанное»", "Коробка «Яблоки»", "Коробка «Апельсины»", "Любая — неважно"], "Берите из «Смешанное» (там не смесь). Если выпало яблоко — там яблоки. Тогда «Яблоки» (ложная этикетка) — апельсины, а «Апельсины» — смесь."],
    "TMP5_6": ["У мужчины три дочери. Произведение их возрастов равно 36. Сумма их возрастов равна номеру соседнего дома (что неоднозначно). Самый старший играет на фортепиано. Каков их возраст?", "Два разных набора коэффициентов по 36 имеют одну и ту же сумму. Слово «самый старый» исключает один набор.", ["2, 2 и 9", "1, 6 и 6", "3, 3 и 4", "1, 4 и 9"], "Наборы факторов из 36, суммирующиеся до 13: {1,6,6} и {2,2,9}. Поскольку существует «самый старый» (уникальный), он должен быть {2, 2, 9}."],
    "TMP5_7": ["Задача Монти Холла: вы выбираете дверь 1 из 3 (у одной есть машина, у двух — козы). Хозяин открывает дверь №3 и показывает козу. Стоит ли перейти на дверь 2?", "Какова вероятность того, что машина находилась за вашей оригинальной дверью?", ["Да — переключение выигрывает в 2/3 случаев", "Нет, в любом случае 50/50.", "Это не имеет значения", "Нет — ваш первый выбор обычно правильный"], "Ваш первоначальный выбор имел шанс 1/3. Оставшаяся дверь теперь несет в себе остальные 2/3. Переключение удваивает ваши шансы."],
    "TMP5_8": ["Сколько квадратов любого размера на стандартной шахматной доске 8×8?", "Считайте отдельно квадраты 1×1, 2×2, … 8×8.", ["204", "64", "256", "100"], "Сумма: 8² + 7² + … + 1² = 204."],
    "TMP5_9": ["Сколько равна сумма всех целых чисел от 1 до 100?", "Используйте формулу Гаусса: n(n + 1)/2.", ["5050", "5000", "10000", "10100"], "100 × 101 / 2 = 5050."],
    "TMP5_10": ["Сколько нулей в конце числа 100!?", "Нули в конце даёт множитель 10 = 2×5; пятёрок обычно меньше — посчитайте степень 5 в разложении.", ["24", "20", "25", "10"], "⌊100/5⌋ + ⌊100/25⌋ = 20 + 4 = 24."],
    "TMP5_11": ["Фермер перевозит через реку волка, козу и капусту. В лодке — фермер и один предмет. Волк съест козу без фермера; коза съест капусту. С чего начать?", "Какую пару можно безопасно оставить без фермера на берегу?", ["Коза", "Волк", "Капуста", "Не важно"], "Сначала коза. Волк с капустой остаются вместе безопасно. Дальше — переправы с возвратами."],
    "TMP5_12": ["Начиная с одной пары кроликов, они созревают за месяц и дают по одной новой паре каждый месяц после созревания. Сколько пар через 6 месяцев?", "Это числа Фибоначчи: 1, 1, 2, 3, 5, 8, …", ["8", "13", "6", "10"], "По месяцам: 1, 1, 2, 3, 5, 8 пар."],
    "TMP5_13": ["Каково минимальное число ходов в задаче о Ханойской башне с 5 дисками?", "Формула: 2ⁿ − 1, где n — число дисков.", ["31", "32", "63", "15"], "2⁵ − 1 = 31 ход."],
    "TMP5_14": ["Какое минимальное количество человек должно находиться в комнате, чтобы вероятность того, что у двоих из них один день рождения, была более 50%?", "Это знаменитый парадокс дня рождения — ответ гораздо меньше, чем можно было бы ожидать.", ["23", "50", "183", "365"], "При наличии всего 23 человек вероятность того, что хотя бы у двоих один день рождения, превышает 50%."],
    "TMP5_15": ["Какова приблизительная вероятность того, что в комнате, состоящей из 23 человек, по крайней мере у двоих из них один день рождения?", "Это результат парадокса дня рождения.", ["Около 50%", "Около 6%", "Около 25%", "Около 75%"], "При наличии 23 человек вероятность составляет примерно 50,7% — что противоречит здравому смыслу."],
    "TMP5_16": ["На острове рыцари всегда говорят правду, лжецы всегда лгут. А говорит: «Мы оба лжецы». Кто А?", "Мог бы рыцарь правдиво сказать это?", ["Лжец", "Рыцарь", "Нельзя определить", "Ни то ни другое"], "Рыцарь не мог бы сказать «мы оба лжецы». Значит, А лжёт; утверждение ложно — не оба лжецы, второй — рыцарь."],
    "TMP5_17": ["Чему равна сумма внутренних углов семиугольника?", "Формула (n − 2) × 180°.", ["900°", "720°", "1080°", "1260°"], "(7 − 2) × 180° = 900°."],
    "TMP5_18": ["Сколько квадратов всех размеров существует в сетке 4×4?", "Сосчитайте квадраты 1×1, 2×2, 3×3 и 4×4.", ["30", "16", "20", "25"], "4² + 3² + 2² + 1² = 16 + 9 + 4 + 1 = 30."],
    "TMP5_19": ["Если подбросить честную монету 3 раза, какова вероятность выпадения хотя бы одного орла?", "Проще посчитать дополнение: вероятность выпадения НЕТ орла вообще.", ["7/8", "3/4", "1/2", "1/8"], "P(без головок) = (1/2)³ = 1/8. P(хотя бы одна голова) = 1 − 1/8 = 7/8."],
    "TMP5_20": ["Сколько прямоугольников можно составить из линий сетки 3×3 (4 горизонтальных и 4 вертикальных линии)?", "Прямоугольник определяется выбором двух горизонтальных и двух вертикальных линий.", ["36", "18", "24", "9"], "C(4,2) × C(4,2) = 6 × 6 = 36 прямоугольников."],
  }
});
